import React, { useState, useEffect } from 'react';
import { FinancialReport, MiscItem, UserSession } from '../types';
import { RefreshCw, CheckCircle, Calculator, Info, Plus, Trash2 } from 'lucide-react';
import { getReports, saveReport, getTransactions } from '../services/storageService';

interface ReportFormProps {
  session: UserSession;
  initialData?: FinancialReport;
  onFinished: () => void;
  onCancel: () => void;
}

export const ReportForm: React.FC<ReportFormProps> = ({ session, initialData, onFinished, onCancel }) => {
  const [date, setDate] = useState(initialData?.date || new Date().toISOString().split('T')[0]);
  const [offers, setOffers] = useState(initialData?.offers || 0);
  const [tithes, setTithes] = useState(initialData?.tithes || 0);
  const [financialRevenue, setFinancialRevenue] = useState(initialData?.financialRevenue || 0);
  const [specialOffers, setSpecialOffers] = useState(initialData?.specialOffers || 0);
  const [otherRevenues, setOtherRevenues] = useState<MiscItem[]>(initialData?.otherRevenues || []);

  const [rent, setRent] = useState(initialData?.rent || 0);
  const [water, setWater] = useState(initialData?.water || 0);
  const [energy, setEnergy] = useState(initialData?.energy || 0);
  const [otherExpenses, setOtherExpenses] = useState<MiscItem[]>(initialData?.otherExpenses || []);

  const [isSaving, setIsSaving] = useState(false);
  const [previousBalance, setPreviousBalance] = useState(initialData?.previousBalance || 0);

  useEffect(() => {
    if (!initialData) fetchLastBalance();
  }, [session.institution, initialData]);

  const fetchLastBalance = async () => {
    try {
      const reports = await getReports(session.institution);
      if (reports.length > 0) setPreviousBalance(reports[0].currentBalance);
    } catch (e) { console.error(e); }
  };

  const importTransactions = async () => {
    const txs = await getTransactions(session.institution);
    const weeklyOffers = txs.filter(t => t.type === 'RECEITA' && t.category === 'Oferta').reduce((a, b) => a + b.value, 0);
    const weeklyTithes = txs.filter(t => t.type === 'RECEITA' && t.category === 'Dizimo').reduce((a, b) => a + b.value, 0);
    const weeklyFinancial = txs.filter(t => t.type === 'RECEITA' && t.category === 'Receita Financeira').reduce((a, b) => a + b.value, 0);

    setOffers(weeklyOffers);
    setTithes(weeklyTithes);
    setFinancialRevenue(weeklyFinancial);
    alert('Importação concluída: Dízimos, Ofertas e Receitas Financeiras sincronizados.');
  };

  const addOtherRevenue = () => {
    setOtherRevenues([...otherRevenues, { id: crypto.randomUUID(), description: '', value: 0 }]);
  };

  const removeOtherRevenue = (id: string) => {
    setOtherRevenues(otherRevenues.filter(item => item.id !== id));
  };

  const updateOtherRevenue = (id: string, field: 'description' | 'value', value: any) => {
    setOtherRevenues(otherRevenues.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const addOtherExpense = () => {
    setOtherExpenses([...otherExpenses, { id: crypto.randomUUID(), description: '', value: 0 }]);
  };

  const removeOtherExpense = (id: string) => {
    setOtherExpenses(otherExpenses.filter(item => item.id !== id));
  };

  const updateOtherExpense = (id: string, field: 'description' | 'value', value: any) => {
    setOtherExpenses(otherExpenses.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  // CÁLCULOS TOTAIS
  const sumOtherRevenues = otherRevenues.reduce((acc, curr) => acc + (curr.value || 0), 0);
  const totalRevenue = offers + tithes + financialRevenue + specialOffers + sumOtherRevenues;

  const sedeExpense = totalRevenue * 0.20;
  const prebendaExpense = totalRevenue * 0.20;
  const revenue60 = totalRevenue * 0.60;

  const sumOtherExpenses = otherExpenses.reduce((acc, curr) => acc + (curr.value || 0), 0);
  const totalFixedExpenses = rent + water + energy + sumOtherExpenses;
  const saldoGU = revenue60 - totalFixedExpenses;
  const currentBalance = previousBalance + saldoGU;

  const formatBRL = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);

    const report: FinancialReport = {
      id: initialData?.id || crypto.randomUUID(),
      date, 
      institutionName: session.institution, 
      reporterName: session.name, 
      userId: session.id,
      locked: false,
      offers, 
      tithes, 
      financialRevenue,
      specialOffers,
      otherRevenues,
      rent, 
      water, 
      energy, 
      otherExpenses,
      totalRevenue, 
      totalFixedExpenses,
      sedeExpense, 
      prebendaExpense, 
      totalExpenses: sedeExpense + prebendaExpense + totalFixedExpenses,
      saldoGU, 
      currentBalance, 
      previousBalance, 
      attachments: [],
      createdAt: initialData?.createdAt || new Date().toISOString()
    };

    try {
      await saveReport(report);
      onFinished();
    } catch (err) {
      alert('Erro crítico ao salvar relatório. Verifique os campos e tente novamente.');
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="space-y-6 pb-20 animate-in slide-in-from-bottom-4 duration-700">
      <div className="bg-white rounded-[2.5rem] p-8 md:p-12 shadow-soft border border-slate-50">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-12">
          <div>
            <h2 className="text-2xl font-black uppercase tracking-tight text-slate-900">Fechamento Semanal</h2>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">Consolidação de Entradas e Repasses GU</p>
          </div>
          <button 
            type="button" 
            onClick={importTransactions} 
            className="flex items-center justify-center gap-2 px-6 py-4 bg-indigo-50 text-indigo-600 rounded-2xl font-black text-[10px] uppercase tracking-widest active-scale border border-indigo-100 shadow-sm"
          >
            <RefreshCw size={16} /> Importar Lançamentos Diários
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-12">
          {/* Sessão de Entradas */}
          <section className="space-y-6">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded-full bg-emerald-100 text-emerald-600 flex items-center justify-center">
                  <Calculator size={16}/>
                </div>
                <h3 className="text-xs font-black uppercase text-slate-900 tracking-widest">Receitas do Período (100%)</h3>
              </div>
              <button 
                type="button" 
                onClick={addOtherRevenue}
                className="flex items-center gap-1.5 text-[8px] font-black uppercase text-indigo-600 bg-indigo-50 px-3 py-2 rounded-lg hover:bg-indigo-100 transition-colors"
              >
                <Plus size={12}/> Adicionar Receita
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              <div className="space-y-1">
                <label className="text-[8px] font-black text-slate-400 uppercase ml-3">Dízimos</label>
                <input type="number" step="0.01" value={tithes || ''} onChange={e => setTithes(parseFloat(e.target.value) || 0)} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs outline-none focus:ring-2 focus:ring-indigo-500/10 border border-transparent focus:border-indigo-100 transition-all" placeholder="0,00" />
              </div>
              <div className="space-y-1">
                <label className="text-[8px] font-black text-slate-400 uppercase ml-3">Ofertas Gerais</label>
                <input type="number" step="0.01" value={offers || ''} onChange={e => setOffers(parseFloat(e.target.value) || 0)} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs outline-none focus:ring-2 focus:ring-indigo-500/10 border border-transparent focus:border-indigo-100" placeholder="0,00" />
              </div>
              <div className="space-y-1">
                <label className="text-[8px] font-black text-indigo-500 uppercase ml-3 flex items-center gap-1">Receita Financeira <Info size={10}/></label>
                <input type="number" step="0.01" value={financialRevenue || ''} onChange={e => setFinancialRevenue(parseFloat(e.target.value) || 0)} className="w-full p-4 bg-indigo-50/50 rounded-2xl font-black text-xs outline-none focus:ring-2 focus:ring-indigo-500/20 border border-indigo-100/50" placeholder="Juros/Rendimentos" />
              </div>
              <div className="space-y-1">
                <label className="text-[8px] font-black text-slate-400 uppercase ml-3">Ofertas Especiais</label>
                <input type="number" step="0.01" value={specialOffers || ''} onChange={e => setSpecialOffers(parseFloat(e.target.value) || 0)} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs outline-none focus:ring-2 focus:ring-indigo-500/10 border border-transparent focus:border-indigo-100" placeholder="0,00" />
              </div>
            </div>

            {/* Outras Receitas Dinâmicas */}
            {otherRevenues.length > 0 && (
              <div className="space-y-3 mt-4 animate-in fade-in duration-300">
                {otherRevenues.map((item) => (
                  <div key={item.id} className="flex gap-3 items-center bg-slate-50/50 p-3 rounded-2xl border border-slate-100 group">
                    <input 
                      type="text" 
                      value={item.description} 
                      onChange={e => updateOtherRevenue(item.id, 'description', e.target.value)}
                      placeholder="Descrição da Receita Extra" 
                      className="flex-1 bg-white p-3 rounded-xl text-[10px] font-bold uppercase border border-slate-100 outline-none focus:border-indigo-200"
                    />
                    <input 
                      type="number" 
                      step="0.01"
                      value={item.value || ''} 
                      onChange={e => updateOtherRevenue(item.id, 'value', parseFloat(e.target.value) || 0)}
                      placeholder="0,00" 
                      className="w-28 bg-white p-3 rounded-xl text-[10px] font-black border border-slate-100 outline-none focus:border-indigo-200"
                    />
                    <button type="button" onClick={() => removeOtherRevenue(item.id)} className="p-2 text-slate-300 hover:text-rose-500 transition-colors">
                      <Trash2 size={16}/>
                    </button>
                  </div>
                ))}
              </div>
            )}
          </section>

          {/* Sessão de Despesas GU */}
          <section className="space-y-6">
            <div className="flex items-center justify-between">
              <h3 className="text-xs font-black uppercase text-slate-900 tracking-widest flex items-center gap-3">
                 <div className="w-8 h-8 rounded-full bg-rose-100 text-rose-600 flex items-center justify-center"><Calculator size={16}/></div>
                 Custos Operacionais GU (Dos 60%)
              </h3>
              <button 
                type="button" 
                onClick={addOtherExpense}
                className="flex items-center gap-1.5 text-[8px] font-black uppercase text-rose-600 bg-rose-50 px-3 py-2 rounded-lg hover:bg-rose-100 transition-colors"
              >
                <Plus size={12}/> Adicionar Despesa
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="space-y-1">
                <label className="text-[8px] font-black text-slate-400 uppercase ml-3">Aluguel</label>
                <input type="number" step="0.01" value={rent || ''} onChange={e => setRent(parseFloat(e.target.value) || 0)} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs outline-none border border-transparent focus:border-rose-100" />
              </div>
              <div className="space-y-1">
                <label className="text-[8px] font-black text-slate-400 uppercase ml-3">Energia</label>
                <input type="number" step="0.01" value={energy || ''} onChange={e => setEnergy(parseFloat(e.target.value) || 0)} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs outline-none border border-transparent focus:border-rose-100" />
              </div>
              <div className="space-y-1">
                <label className="text-[8px] font-black text-slate-400 uppercase ml-3">Água</label>
                <input type="number" step="0.01" value={water || ''} onChange={e => setWater(parseFloat(e.target.value) || 0)} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs outline-none border border-transparent focus:border-rose-100" />
              </div>
            </div>

            {/* Outras Despesas Dinâmicas */}
            {otherExpenses.length > 0 && (
              <div className="space-y-3 mt-4 animate-in fade-in duration-300">
                {otherExpenses.map((item) => (
                  <div key={item.id} className="flex gap-3 items-center bg-slate-50/50 p-3 rounded-2xl border border-slate-100">
                    <input 
                      type="text" 
                      value={item.description} 
                      onChange={e => updateOtherExpense(item.id, 'description', e.target.value)}
                      placeholder="Descrição da Despesa Extra" 
                      className="flex-1 bg-white p-3 rounded-xl text-[10px] font-bold uppercase border border-slate-100 outline-none focus:border-rose-200"
                    />
                    <input 
                      type="number" 
                      step="0.01"
                      value={item.value || ''} 
                      onChange={e => updateOtherExpense(item.id, 'value', parseFloat(e.target.value) || 0)}
                      placeholder="0,00" 
                      className="w-28 bg-white p-3 rounded-xl text-[10px] font-black border border-slate-100 outline-none focus:border-rose-200"
                    />
                    <button type="button" onClick={() => removeOtherExpense(item.id)} className="p-2 text-slate-300 hover:text-rose-500 transition-colors">
                      <Trash2 size={16}/>
                    </button>
                  </div>
                ))}
              </div>
            )}
          </section>

          {/* Resumo Consolidado */}
          <div className="bg-slate-900 rounded-[2.5rem] p-8 md:p-12 text-white shadow-2xl relative overflow-hidden">
             <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/10 rounded-full -mr-32 -mt-32 blur-3xl pointer-events-none" />

             <div className="grid grid-cols-1 md:grid-cols-2 gap-12 relative z-10">
                <div className="space-y-5">
                  <div className="flex justify-between items-end pb-4 border-b border-white/10">
                    <span className="text-[9px] font-black uppercase text-slate-400 tracking-widest">Total Bruto (100%)</span>
                    <span className="text-2xl font-black">{formatBRL(totalRevenue)}</span>
                  </div>

                  <div className="space-y-3">
                    <div className="flex justify-between items-center text-[8px] font-bold text-slate-400 uppercase">
                      <span>Repasse Sede (20%)</span>
                      <span className="text-rose-400">- {formatBRL(sedeExpense)}</span>
                    </div>
                    <div className="flex justify-between items-center text-[8px] font-bold text-slate-400 uppercase">
                      <span>Prebenda Ministerial (20%)</span>
                      <span className="text-rose-400">- {formatBRL(prebendaExpense)}</span>
                    </div>
                    <div className="flex justify-between items-center text-[10px] font-black text-emerald-400 uppercase pt-2">
                      <span>Disponível GU (60%)</span>
                      <span>{formatBRL(revenue60)}</span>
                    </div>
                    <div className="flex justify-between items-center text-[8px] font-bold text-slate-500 uppercase">
                      <span>Custos Unidade (Fixos + Outros)</span>
                      <span className="text-rose-400">- {formatBRL(totalFixedExpenses)}</span>
                    </div>
                  </div>
                </div>

                <div className="bg-white/5 backdrop-blur-md p-8 rounded-[2rem] border border-white/10 flex flex-col justify-center">
                   <p className="text-[9px] font-black uppercase text-indigo-400 tracking-widest mb-2">Saldo Final em Caixa</p>
                   <h4 className="text-4xl font-black tracking-tight">{formatBRL(currentBalance)}</h4>
                   <p className="text-[7px] font-bold text-slate-500 uppercase mt-4">Calculado: Saldo Anterior ({formatBRL(previousBalance)}) + Saldo GU ({formatBRL(saldoGU)})</p>
                </div>
             </div>

             <div className="mt-12 flex gap-4">
               <button 
                type="button" 
                onClick={onCancel} 
                className="flex-1 py-5 rounded-2xl font-black text-[10px] uppercase tracking-widest border border-white/10 hover:bg-white/5 transition-colors"
               >
                 Cancelar
               </button>
               <button 
                type="submit" 
                disabled={isSaving} 
                className="flex-[2] bg-indigo-600 hover:bg-indigo-500 py-5 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all shadow-xl shadow-indigo-500/20 active-scale flex items-center justify-center gap-2"
               >
                 {isSaving ? <RefreshCw className="animate-spin" size={20}/> : <><CheckCircle size={18}/> Finalizar e Salvar Relatório</>}
               </button>
             </div>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { ReportForm } from './components/ReportForm';
import { ReportHistory } from './components/ReportHistory';
import { AdminDashboard } from './components/AdminDashboard';
import { UserManagement } from './components/UserManagement';
import { TrashManager } from './components/TrashManager';
import { Settings } from './components/Settings';
import { Logo } from './components/Logo';
import { UserSession, FinancialReport } from './types';
import { getUserByUsername } from './services/storageService';
import { Lock, UserCircle, ArrowRight, RefreshCw, AlertCircle, Sparkles } from 'lucide-react';

const App: React.FC = () => {
  const [session, setSession] = useState<UserSession | null>(null);
  const [currentView, setCurrentView] = useState<'REPORT_NEW' | 'HISTORY' | 'DASHBOARD' | 'USERS' | 'TRASH' | 'SETTINGS'>('HISTORY');
  const [editingReport, setEditingReport] = useState<FinancialReport | null>(null);
  const [isReadOnly, setIsReadOnly] = useState(false);
  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');
  const [isLoggingIn, setIsLoggingIn] = useState(false);

  const handleLoginSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const userLower = loginUsername.toLowerCase().trim();
    const passRaw = loginPassword.trim();

    if (!userLower || !passRaw) {
      setLoginError('Informe usuário e senha');
      return;
    }

    setLoginError('');
    setIsLoggingIn(true);

    if (userLower === 'adm' && passRaw === 'adm') {
      setSession({
        id: 'admin-master',
        name: 'Administrador Geral',
        role: 'ADMIN',
        institution: 'Sede Administrativa'
      });
      setCurrentView('DASHBOARD');
      setIsLoggingIn(false);
      return;
    }

    try {
      const user = await getUserByUsername(userLower);
      if (!user) {
        setLoginError('Usuário não encontrado');
        setIsLoggingIn(false);
        return;
      }
      if (user.password !== passRaw) {
        setLoginError('Senha incorreta');
        setIsLoggingIn(false);
        return;
      }
      if (!user.active && user.role !== 'ADMIN') {
        setLoginError('Conta inativa. Contate o administrador.');
        setIsLoggingIn(false);
        return;
      }

      setSession({ 
        id: user.id, 
        name: user.name, 
        phone: user.phone,
        photo: user.photo,
        role: user.role, 
        institution: (user.institution || 'Geral').trim()
      });

      setCurrentView(user.role === 'ADMIN' ? 'DASHBOARD' : 'HISTORY');
    } catch (err: any) {
      setLoginError('Erro ao acessar o servidor. Tente novamente.');
    } finally {
      setIsLoggingIn(false);
    }
  };

  const handleOpenReport = (report: FinancialReport, readOnly: boolean = false) => {
    setEditingReport(report);
    setIsReadOnly(readOnly);
    setCurrentView('REPORT_NEW');
  };

  const renderContent = () => {
    if (!session) return null;
    switch (currentView) {
      case 'DASHBOARD': return <AdminDashboard session={session} />;
      case 'REPORT_NEW': return (
        <ReportForm 
          session={session} 
          initialData={editingReport || undefined}
          readOnly={isReadOnly}
          onFinished={() => { setEditingReport(null); setIsReadOnly(false); setCurrentView('HISTORY'); }} 
          onCancel={() => { setEditingReport(null); setIsReadOnly(false); setCurrentView('HISTORY'); }} 
        />
      );
      case 'HISTORY': return (
        <ReportHistory 
          session={session} 
          onEdit={(rep, ro) => handleOpenReport(rep, ro)}
          onBack={() => setCurrentView('HISTORY')} 
          onGoToTrash={() => setCurrentView('TRASH')}
        />
      );
      case 'USERS': return <UserManagement session={session} />;
      case 'TRASH': return <TrashManager session={session} />;
      case 'SETTINGS': return <Settings />;
      default: return <ReportHistory session={session} onEdit={handleOpenReport} onBack={() => setCurrentView('HISTORY')} onGoToTrash={() => setCurrentView('TRASH')} />;
    }
  };

  if (!session) {
    return (
      <div className="min-h-screen flex items-center justify-center p-5 mesh-bg">
        <div className="max-w-xs w-full animate-in zoom-in-95 duration-700">
          <div className="bg-white/90 backdrop-blur-3xl p-8 rounded-[2.5rem] shadow-3xl border border-white flex flex-col items-center">
            <div className="mb-8 p-3 bg-indigo-600 rounded-2xl shadow-lg shadow-indigo-200">
              <Logo size="sm" className="brightness-0 invert w-6 h-6" />
            </div>

            <div className="text-center mb-8">
              <h1 className="text-xl font-black text-slate-900 tracking-tight uppercase">Portal ADGU</h1>
              <p className="text-indigo-600 text-[8px] font-black uppercase tracking-[0.3em] mt-1">Gestão Ministerial</p>
            </div>

            <form onSubmit={handleLoginSubmit} className="space-y-4 w-full">
              <div className="space-y-1">
                <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Usuário</label>
                <div className="relative">
                  <UserCircle className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                  <input type="text" value={loginUsername} onChange={e => setLoginUsername(e.target.value)} className="w-full pl-11 pr-4 py-3.5 rounded-xl bg-slate-50 border border-slate-100 outline-none font-bold text-xs focus:ring-2 focus:ring-indigo-500/10 transition-all" placeholder="Seu login" autoCapitalize="none" disabled={isLoggingIn} />
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Senha</label>
                <div className="relative">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                  <input type="password" value={loginPassword} onChange={e => setLoginPassword(e.target.value)} className="w-full pl-11 pr-4 py-3.5 rounded-xl bg-slate-50 border border-slate-100 outline-none font-bold text-xs focus:ring-2 focus:ring-indigo-500/10 transition-all" placeholder="••••" disabled={isLoggingIn} />
                </div>
              </div>
              {loginError && (
                <div className="bg-rose-50 p-3 rounded-xl border border-rose-100 flex items-center gap-2 animate-in shake duration-300">
                  <AlertCircle size={14} className="text-rose-500 shrink-0" />
                  <p className="text-rose-600 text-[8px] font-black uppercase leading-tight">{loginError}</p>
                </div>
              )}
              <button type="submit" disabled={isLoggingIn} className="w-full bg-slate-900 text-white font-black py-4 rounded-xl shadow-xl active-scale transition-all uppercase text-[9px] flex items-center justify-center gap-2 hover:bg-slate-800 disabled:opacity-50">
                {isLoggingIn ? <RefreshCw className="animate-spin" size={14} /> : 'Acessar Painel'} <ArrowRight size={14} />
              </button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout session={session} currentView={currentView} onViewChange={setCurrentView} onLogout={() => { setSession(null); setLoginUsername(''); setLoginPassword(''); setCurrentView('HISTORY'); }}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { UserSession } from '../types';
import { Logo } from './Logo';
