interface UserAvatarProps {
  size?: 'sm' | 'md' | 'lg';
  photo?: string;
  name: string;
}

const UserAvatar: React.FC<UserAvatarProps> = ({ size = 'md', photo, name }) => {
  const sizeClasses = {
    sm: 'w-7 h-7 text-[8px]',
    md: 'w-10 h-10 text-[10px]',
    lg: 'w-16 h-16 text-xl'
  };
  return (
    <div className={`${sizeClasses[size]} rounded-2xl bg-indigo-600 text-white flex items-center justify-center font-black shadow-lg flex-shrink-0 uppercase border-2 border-white/20 overflow-hidden`}>
      {photo ? <img src={photo} className="w-full h-full object-cover" alt="" /> : name.charAt(0)}
