import React, { useState, useEffect, useRef } from 'react';
import { FinancialReport, MiscItem, UserSession } from '../types';
import { CheckCircle, Calculator, Info, Plus, Trash2, ArrowRight, ArrowLeft, UploadCloud, RefreshCw, FileText } from 'lucide-react';
import { saveReport, getSettings } from '../services/storageService';

interface ReportFormProps {
  session: UserSession;
  initialData?: FinancialReport;
  readOnly?: boolean;
  onFinished: () => void;
  onCancel: () => void;
}

type FormTab = 'RECEITAS' | 'DESPESAS' | 'ANEXOS' | 'RESUMO';

export const ReportForm: React.FC<ReportFormProps> = ({ session, initialData, readOnly = false, onFinished, onCancel }) => {
  const [activeTab, setActiveTab] = useState<FormTab>('RECEITAS');
  const [date, setDate] = useState(initialData?.date || new Date().toISOString().split('T')[0]);
  const [offers, setOffers] = useState(initialData?.offers || 0);
  const [tithes, setTithes] = useState(initialData?.tithes || 0);
  const [financialRevenue, setFinancialRevenue] = useState(initialData?.financialRevenue || 0);
  const [specialOffers, setSpecialOffers] = useState(initialData?.specialOffers || 0);
  const [otherRevenues, setOtherRevenues] = useState<MiscItem[]>(initialData?.otherRevenues || []);
  const [otherExpenses, setOtherExpenses] = useState<MiscItem[]>(initialData?.otherExpenses || []);
  const [rent, setRent] = useState(initialData?.rent || 0);
  const [water, setWater] = useState(initialData?.water || 0);
  const [energy, setEnergy] = useState(initialData?.energy || 0);
  const [attachments, setAttachments] = useState<{ name: string; type: string; data: string }[]>(initialData?.attachments || []);
  const [isSaving, setIsSaving] = useState(false);
  const [isCompressing, setIsCompressing] = useState(false);
  const [previousBalance, setPreviousBalance] = useState(initialData?.previousBalance || 0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isCamposBelos = (initialData?.institutionName || session.institution).toLowerCase().replace(/\s+/g, '').includes('camposbelos');

  const compressImage = (base64Str: string): Promise<string> => {
    return new Promise((resolve) => {
      const img = new Image();
      img.src = base64Str;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX_WIDTH = 1200;
        let width = img.width;
        let height = img.height;
        if (width > MAX_WIDTH) { height *= MAX_WIDTH / width; width = MAX_WIDTH; }
        canvas.width = width; canvas.height = height;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL('image/jpeg', 0.6));
      };
    });
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (readOnly) return;
    const files = e.target.files;
    if (!files) return;
    setIsCompressing(true);
    for (const file of Array.from(files)) {
      try {
        const base64: string = await new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
        });
        const compressed = await compressImage(base64);
        setAttachments(prev => [...prev, { name: file.name, type: 'image/jpeg', data: compressed }]);
      } catch (err) { console.error(err); }
    }
    setIsCompressing(false);
  };

  const sumOtherRevenues = otherRevenues.reduce((acc, curr) => acc + (curr.value || 0), 0);
  const totalRevenue = (Number(offers) || 0) + (Number(tithes) || 0) + (Number(financialRevenue) || 0) + (Number(specialOffers) || 0) + sumOtherRevenues;
  const sedeExpense = isCamposBelos ? 0 : totalRevenue * 0.20;
  const prebendaExpense = isCamposBelos ? 0 : totalRevenue * 0.20;
  const revenue60 = isCamposBelos ? totalRevenue : totalRevenue * 0.60;
  const sumOtherExpenses = otherExpenses.reduce((acc, curr) => acc + (curr.value || 0), 0);
  const totalFixedExpenses = (Number(rent) || 0) + (Number(water) || 0) + (Number(energy) || 0) + sumOtherExpenses;
  const totalExpenses = sedeExpense + prebendaExpense + totalFixedExpenses;
  const saldoGU = revenue60 - totalFixedExpenses;
  const currentBalance = previousBalance + saldoGU;

  const formatBRL = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

  const handleSubmit = async () => {
    if (readOnly && session.role !== 'ADMIN') { onFinished(); return; }
    setIsSaving(true);
    const report: FinancialReport = {
      id: initialData?.id || crypto.randomUUID(),
      date, institutionName: initialData?.institutionName || session.institution,
      reporterName: initialData?.reporterName || session.name, userId: initialData?.userId || session.id,
      locked: initialData?.locked || false, offers, tithes, financialRevenue, specialOffers, otherRevenues,
      rent, water, energy, otherExpenses, totalRevenue, totalFixedExpenses, sedeExpense, prebendaExpense,
      totalExpenses, saldoGU, currentBalance, previousBalance, attachments, createdAt: initialData?.createdAt || new Date().toISOString()
    };
    try {
      await saveReport(report);
      onFinished();
    } catch (err: any) { alert("Erro ao salvar relatório."); } finally { setIsSaving(false); }
  };

  return (
    <div className="space-y-8 max-w-4xl mx-auto animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 px-4">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-3 bg-white text-slate-400 rounded-xl shadow-sm"><ArrowLeft size={20}/></button>
          <div>
            <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">{readOnly ? 'Visualização' : 'Novo Fechamento'}</h2>
            <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">{session.institution}</p>
          </div>
        </div>
      </div>

      <div className="flex bg-white p-2 rounded-[1.5rem] shadow-soft border border-slate-50 overflow-x-auto">
        {(['RECEITAS', 'DESPESAS', 'ANEXOS', 'RESUMO'] as FormTab[]).map(tab => (
          <button key={tab} onClick={() => setActiveTab(tab)} className={`flex-1 py-4 px-6 rounded-2xl text-[9px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>{tab}</button>
        ))}
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 p-8 shadow-sm min-h-[400px]">
        {activeTab === 'RECEITAS' && (
          <div className="space-y-6 animate-in slide-in-from-right-4">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Data Referência</label>
                  <input type="date" disabled={readOnly} value={date} onChange={e => setDate(e.target.value)} className="w-full p-4 bg-slate-50 rounded-2xl border border-transparent font-bold text-xs" />
                </div>
                <div className="space-y-1">
                  <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Saldo Anterior</label>
                  <input type="number" disabled={readOnly} value={previousBalance} onChange={e => setPreviousBalance(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl border border-transparent font-black text-xs" />
                </div>
             </div>
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-4">
                <div className="space-y-4">
                   <h4 className="text-[10px] font-black uppercase text-indigo-500 border-b border-indigo-50 pb-2">Entradas</h4>
                   {[
                     { label: 'Dízimos', val: tithes, set: setTithes },
                     { label: 'Ofertas Gerais', val: offers, set: setOffers },
                     { label: 'Ofertas Especiais', val: specialOffers, set: setSpecialOffers },
                     { label: 'Receita Financeira', val: financialRevenue, set: setFinancialRevenue }
                   ].map(item => (
                     <div key={item.label} className="space-y-1">
                        <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">{item.label}</label>
                        <input type="number" disabled={readOnly} value={item.val || ''} onChange={e => item.set(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs" placeholder="0,00" />
                     </div>
                   ))}
                </div>
                <div className="space-y-4">
                   <div className="flex justify-between items-center border-b border-slate-50 pb-2">
                     <h4 className="text-[10px] font-black uppercase text-slate-900">Outras Receitas</h4>
                     {!readOnly && <button onClick={() => setOtherRevenues([...otherRevenues, { id: crypto.randomUUID(), description: '', value: 0 }])} className="p-2 bg-indigo-50 text-indigo-600 rounded-lg"><Plus size={14}/></button>}
                   </div>
                   {otherRevenues.map(item => (
                     <div key={item.id} className="flex gap-2">
                        <input type="text" disabled={readOnly} value={item.description} onChange={e => setOtherRevenues(otherRevenues.map(i => i.id === item.id ? {...i, description: e.target.value} : i))} className="flex-1 p-3 bg-slate-50 rounded-xl text-[10px] font-bold" placeholder="Descrição" />
                        <input type="number" disabled={readOnly} value={item.value || ''} onChange={e => setOtherRevenues(otherRevenues.map(i => i.id === item.id ? {...i, value: Number(e.target.value)} : i))} className="w-24 p-3 bg-slate-50 rounded-xl text-[10px] font-black" placeholder="0,00" />
                        {!readOnly && <button onClick={() => setOtherRevenues(otherRevenues.filter(i => i.id !== item.id))} className="p-2 text-rose-500"><Trash2 size={14}/></button>}
                     </div>
                   ))}
                </div>
             </div>
          </div>
        )}

        {activeTab === 'DESPESAS' && (
          <div className="space-y-6 animate-in slide-in-from-right-4">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-4">
                   <h4 className="text-[10px] font-black uppercase text-rose-500 border-b border-rose-50 pb-2">Despesas Fixas</h4>
                   {[
                     { label: 'Aluguel Unidade', val: rent, set: setRent },
                     { label: 'Energia Elétrica', val: energy, set: setEnergy },
                     { label: 'Água / Saneamento', val: water, set: setWater }
                   ].map(item => (
                     <div key={item.label} className="space-y-1">
                        <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">{item.label}</label>
                        <input type="number" disabled={readOnly} value={item.val || ''} onChange={e => item.set(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs" />
                     </div>
                   ))}
                </div>
                <div className="space-y-4">
                   <div className="flex justify-between items-center border-b border-slate-50 pb-2">
                     <h4 className="text-[10px] font-black uppercase text-slate-900">Outras Despesas</h4>
                     {!readOnly && <button onClick={() => setOtherExpenses([...otherExpenses, { id: crypto.randomUUID(), description: '', value: 0 }])} className="p-2 bg-indigo-50 text-indigo-600 rounded-lg"><Plus size={14}/></button>}
                   </div>
                   {otherExpenses.map(item => (
                     <div key={item.id} className="flex gap-2">
                        <input type="text" disabled={readOnly} value={item.description} onChange={e => setOtherExpenses(otherExpenses.map(i => i.id === item.id ? {...i, description: e.target.value} : i))} className="flex-1 p-3 bg-slate-50 rounded-xl text-[10px] font-bold" />
                        <input type="number" disabled={readOnly} value={item.value || ''} onChange={e => setOtherExpenses(otherExpenses.map(i => i.id === item.id ? {...i, value: Number(e.target.value)} : i))} className="w-24 p-3 bg-slate-50 rounded-xl text-[10px] font-black" />
                        {!readOnly && <button onClick={() => setOtherExpenses(otherExpenses.filter(i => i.id !== item.id))} className="p-2 text-rose-500"><Trash2 size={14}/></button>}
                     </div>
                   ))}
                </div>
             </div>
          </div>
        )}

        {activeTab === 'ANEXOS' && (
          <div className="space-y-6 animate-in slide-in-from-right-4">
             {!readOnly && (
               <div onClick={() => fileInputRef.current?.click()} className="border-2 border-dashed border-slate-200 rounded-[2rem] p-12 text-center hover:border-indigo-300 cursor-pointer group">
                 <UploadCloud size={48} className="mx-auto text-slate-300 group-hover:text-indigo-500 mb-4" />
                 <h4 className="text-xs font-black uppercase">Anexar Comprovantes</h4>
                 <input type="file" ref={fileInputRef} className="hidden" multiple accept="image/*" onChange={handleFileChange} />
               </div>
             )}
             <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {attachments.map((at, idx) => (
                  <div key={idx} className="relative rounded-2xl overflow-hidden aspect-square">
                    <img src={at.data} className="w-full h-full object-cover" />
                    {!readOnly && <button onClick={() => setAttachments(attachments.filter((_, i) => i !== idx))} className="absolute top-2 right-2 p-2 bg-rose-600 text-white rounded-lg"><Trash2 size={14}/></button>}
                  </div>
                ))}
             </div>
          </div>
        )}

        {activeTab === 'RESUMO' && (
          <div className="space-y-8 animate-in slide-in-from-right-4">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-3">
                   <h4 className="text-[10px] font-black uppercase text-slate-900 border-b pb-2">Distribuição</h4>
                   <div className="flex justify-between p-4 bg-slate-50 rounded-2xl">
                      <span className="text-[9px] font-black uppercase text-slate-400">Total Bruto</span>
                      <span className="text-[10px] font-black">{formatBRL(totalRevenue)}</span>
                   </div>
                   <div className="flex justify-between p-4 bg-emerald-50 rounded-2xl">
                      <span className="text-[9px] font-black uppercase text-emerald-500">Saldo GU ({isCamposBelos ? '100%' : '60%'})</span>
                      <span className="text-[10px] font-black text-emerald-600">{formatBRL(revenue60)}</span>
                   </div>
                </div>
                <div className="space-y-3">
                   <h4 className="text-[10px] font-black uppercase text-slate-900 border-b pb-2">Resultado Final</h4>
                   <div className="flex justify-between p-4 bg-slate-950 rounded-[2rem] text-white">
                      <span className="text-[10px] font-black uppercase">Saldo Líquido</span>
                      <span className="text-sm font-black text-emerald-400">{formatBRL(saldoGU)}</span>
                   </div>
                   <div className="flex justify-between p-4 bg-slate-50 rounded-2xl border">
                      <span className="text-[9px] font-black uppercase text-slate-400">Caixa Geral</span>
                      <span className="text-[10px] font-black">{formatBRL(currentBalance)}</span>
                   </div>
                </div>
             </div>
          </div>
        )}
      </div>

      <div className="flex gap-4">
        {activeTab !== 'RESUMO' ? (
          <button onClick={() => { const tabs: FormTab[] = ['RECEITAS', 'DESPESAS', 'ANEXOS', 'RESUMO']; const idx = tabs.indexOf(activeTab); setActiveTab(tabs[idx + 1]); }} className="flex-1 py-5 bg-slate-900 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 active-scale">Próxima Etapa <ArrowRight size={18}/></button>
        ) : (
          <button onClick={handleSubmit} disabled={isSaving} className="flex-1 py-5 bg-indigo-600 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 active-scale shadow-xl shadow-indigo-100">
            {isSaving ? <RefreshCw className="animate-spin" size={20}/> : <><CheckCircle size={20}/> Salvar Lançamento</>}
          </button>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { FinancialReport, UserSession } from '../types';
import { getReports, getSettings, softDeleteReport, toggleReportLock, isCompetenceLocked } from '../services/storageService';
import { Calendar, Printer, FileText, Search, RefreshCw, Trash2, Edit3, Lock, Unlock, ImageIcon, X, Send, Download, Eye, MapPin } from 'lucide-react';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface ReportHistoryProps {
  session: UserSession;
  onBack: () => void;
  onEdit?: (report: FinancialReport, readOnly?: boolean) => void;
  onGoToTrash?: () => void;
}

export const ReportHistory: React.FC<ReportHistoryProps> = ({ session, onBack, onEdit, onGoToTrash }) => {
  const [reports, setReports] = useState<FinancialReport[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [closingDay, setClosingDay] = useState(1);
  const [viewingPhotos, setViewingPhotos] = useState<FinancialReport | null>(null);

  const fetchReports = async () => {
    try {
      setLoading(true);
      const settings = await getSettings();
      setClosingDay(settings.closingDay || 1);
      const allReports = await getReports();
      const permitted = allReports.filter(r => session.role === 'ADMIN' || r.institutionName.toLowerCase() === session.institution.toLowerCase());
      setReports(permitted);
    } catch (err) { console.error(err); } finally { setLoading(false); }
  };

  useEffect(() => {
    fetchReports();
    window.addEventListener('reports-updated', fetchReports);
    return () => window.removeEventListener('reports-updated', fetchReports);
  }, []);

  const formatBRL = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

  const generatePDF = async (report: FinancialReport) => {
    const settings = await getSettings();
    const doc = new jsPDF() as any;
    const pageWidth = doc.internal.pageSize.getWidth();
    let currentY = 20;

    // Header
    if (settings.logo) {
      doc.addImage(settings.logo, 'PNG', 15, currentY, 25, 25);
      currentY += 10;
    }
    doc.setFontSize(16); doc.setFont("helvetica", "bold"); doc.setTextColor(30, 41, 59);
    doc.text(settings.institutionName.toUpperCase(), settings.logo ? 45 : 15, currentY + 5);
    doc.setFontSize(9); doc.setFont("helvetica", "normal"); doc.setTextColor(100, 116, 139);
    doc.text(`CNPJ: ${settings.cnpj}`, settings.logo ? 45 : 15, currentY + 11);
    doc.text(`Relatório de Fechamento: ${report.date.split('-').reverse().join('/')}`, settings.logo ? 45 : 15, currentY + 16);
    currentY += 30;

    // Tabelas de Valores
    const tableData = [
      ['Dízimos', formatBRL(report.tithes)],
      ['Ofertas Gerais', formatBRL(report.offers)],
      ['Ofertas Especiais', formatBRL(report.specialOffers)],
      ['Receita Financeira', formatBRL(report.financialRevenue)],
      ...report.otherRevenues.map(r => [r.description, formatBRL(r.value)]),
      [{ content: 'TOTAL BRUTO', styles: { fontStyle: 'bold', fillColor: [241, 245, 249] } }, { content: formatBRL(report.totalRevenue), styles: { fontStyle: 'bold', fillColor: [241, 245, 249], halign: 'right' } }]
    ];

    doc.autoTable({
      startY: currentY,
      head: [['Descrição de Entradas', 'Valor']],
      body: tableData,
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
      columnStyles: { 1: { halign: 'right' } }
    });

    currentY = doc.lastAutoTable.finalY + 10;

    const expenseData = [
      ['Repasse Sede (20%)', formatBRL(report.sedeExpense)],
      ['Prebenda Pastoral (20%)', formatBRL(report.prebendaExpense)],
      ['Aluguel', formatBRL(report.rent)],
      ['Água / Energia', formatBRL(report.water + report.energy)],
      ...report.otherExpenses.map(e => [e.description, formatBRL(e.value)]),
      [{ content: 'TOTAL SAÍDAS', styles: { fontStyle: 'bold', fillColor: [254, 242, 242] } }, { content: formatBRL(report.totalExpenses), styles: { fontStyle: 'bold', fillColor: [254, 242, 242], halign: 'right' } }]
    ];

    doc.autoTable({
      startY: currentY,
      head: [['Detalhamento de Saídas', 'Valor']],
      body: expenseData,
      theme: 'grid',
      headStyles: { fillColor: [244, 63, 94] },
      columnStyles: { 1: { halign: 'right' } }
    });

    currentY = doc.lastAutoTable.finalY + 15;
    doc.setFillColor(15, 23, 42);
    doc.roundedRect(15, currentY, pageWidth - 30, 15, 3, 3, 'F');
    doc.setFontSize(11); doc.setTextColor(255, 255, 255);
    doc.text("SALDO LÍQUIDO DISPONÍVEL (GU):", 22, currentY + 9.5);
    doc.text(formatBRL(report.saldoGU), pageWidth - 22, currentY + 9.5, { align: 'right' });

    doc.save(`Relatorio_${report.institutionName.replace(/\s+/g, '_')}_${report.date}.pdf`);
    return true;
  };

  const shareWhatsApp = async (report: FinancialReport) => {
    await generatePDF(report);
    const phone = "5585920003598";
    const message = `*RELATÓRIO FINANCEIRO ADGU*%0A%0A*Unidade:* ${report.institutionName}%0A*Data:* ${report.date.split('-').reverse().join('/')}%0A*Responsável:* ${report.reporterName}%0A%0A*RESUMO:*%0A- Receita Bruta: ${formatBRL(report.totalRevenue)}%0A- Saídas Totais: ${formatBRL(report.totalExpenses)}%0A- *Saldo Líquido GU:* ${formatBRL(report.saldoGU)}%0A%0A_O PDF foi gerado e baixado no seu dispositivo para anexo._`;
    window.open(`https://wa.me/${phone}?text=${message}`, '_blank');
  };

  const filteredReports = reports.filter(r => 
    r.institutionName.toLowerCase().includes(searchTerm.toLowerCase()) || 
    r.date.includes(searchTerm)
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      <div className="bg-white p-5 rounded-[2rem] border border-slate-100 shadow-sm flex gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
          <input type="text" placeholder="Filtrar por data ou congregação..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-12 pr-4 py-3.5 bg-slate-50 rounded-2xl border border-transparent outline-none font-bold text-xs focus:bg-white focus:border-indigo-100 transition-all" />
        </div>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-20 gap-4"><RefreshCw className="animate-spin text-indigo-500" size={32} /><p className="text-[10px] font-black text-slate-400 uppercase">Buscando Relatórios...</p></div>
      ) : (
        <div className="grid grid-cols-1 gap-3">
          {filteredReports.map((report) => {
            const isLocked = isCompetenceLocked(report.date, closingDay) && session.role !== 'ADMIN';
            return (
              <div key={report.id} className="bg-white p-5 rounded-2xl shadow-sm border border-slate-50 flex flex-col sm:flex-row sm:items-center justify-between group transition-all">
                <div className="flex items-center gap-4 mb-4 sm:mb-0">
                  <div className={`p-3 rounded-xl ${isLocked ? 'bg-amber-50 text-amber-500' : 'bg-slate-50 text-indigo-500'}`}>
                    <Calendar size={20} />
                  </div>
                  <div>
                    <h4 className="text-xs font-black text-slate-900 uppercase">{report.date.split('-').reverse().join('/')}</h4>
                    <p className="text-[7px] font-black text-indigo-500 uppercase">{report.institutionName}</p>
                    <p className="text-[7px] font-bold text-slate-400 uppercase mt-0.5">Saldo: {formatBRL(report.saldoGU)}</p>
                  </div>
                </div>

                <div className="flex items-center gap-2">
                  {report.attachments?.length > 0 && (
                    <button onClick={() => setViewingPhotos(report)} className="p-3 bg-slate-50 text-slate-500 rounded-xl hover:bg-indigo-600 hover:text-white transition-all"><ImageIcon size={18}/></button>
                  )}
                  <button onClick={() => onEdit?.(report, isLocked)} className="p-3 bg-slate-50 text-slate-500 rounded-xl"><Eye size={18}/></button>
                  <button onClick={() => shareWhatsApp(report)} className="p-3 bg-emerald-50 text-emerald-600 rounded-xl hover:bg-emerald-600 hover:text-white transition-all flex items-center gap-2 shadow-sm" title="Enviar para WhatsApp">
                    <Send size={18} />
                    <span className="text-[8px] font-black uppercase">WhatsApp</span>
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {viewingPhotos && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 animate-in fade-in duration-300">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-md" onClick={() => setViewingPhotos(null)} />
          <div className="relative w-full max-w-4xl bg-white rounded-[2.5rem] p-8 shadow-3xl flex flex-col max-h-[90vh]">
             <div className="flex justify-between items-center mb-6">
                <div><h3 className="text-lg font-black text-slate-900 uppercase">Anexos</h3><p className="text-[8px] font-black text-indigo-500 uppercase">{viewingPhotos.institutionName}</p></div>
                <button onClick={() => setViewingPhotos(null)} className="p-2 bg-slate-100 rounded-xl text-slate-400"><X size={24}/></button>
             </div>
             <div className="flex-1 overflow-y-auto grid grid-cols-1 sm:grid-cols-2 gap-4">
                {viewingPhotos.attachments.map((file, idx) => (
                  <div key={idx} className="relative rounded-3xl overflow-hidden border bg-slate-50">
                    <img src={file.data} className="w-full h-64 object-cover" />
                    <button onClick={() => { const l=document.createElement('a'); l.href=file.data; l.download=`anexo_${idx}.jpg`; l.click(); }} className="absolute bottom-4 right-4 p-3 bg-white text-slate-900 rounded-xl shadow-lg"><Download size={16}/></button>
                  </div>
                ))}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { FinancialReport, MiscItem, UserSession } from '../types';
import { CheckCircle, Calculator, Info, Plus, Trash2, ArrowRight, ArrowLeft, UploadCloud, RefreshCw, FileText } from 'lucide-react';
import { saveReport, getSettings } from '../services/storageService';

interface ReportFormProps {
  session: UserSession;
  initialData?: FinancialReport;
  readOnly?: boolean;
  onFinished: () => void;
  onCancel: () => void;
}

type FormTab = 'RECEITAS' | 'DESPESAS' | 'ANEXOS' | 'RESUMO';

export const ReportForm: React.FC<ReportFormProps> = ({ session, initialData, readOnly = false, onFinished, onCancel }) => {
  const [activeTab, setActiveTab] = useState<FormTab>('RECEITAS');
  const [date, setDate] = useState(initialData?.date || new Date().toISOString().split('T')[0]);
  const [offers, setOffers] = useState(initialData?.offers || 0);
  const [tithes, setTithes] = useState(initialData?.tithes || 0);
  const [financialRevenue, setFinancialRevenue] = useState(initialData?.financialRevenue || 0);
  const [specialOffers, setSpecialOffers] = useState(initialData?.specialOffers || 0);
  const [otherRevenues, setOtherRevenues] = useState<MiscItem[]>(initialData?.otherRevenues || []);
  const [otherExpenses, setOtherExpenses] = useState<MiscItem[]>(initialData?.otherExpenses || []);
  const [rent, setRent] = useState(initialData?.rent || 0);
  const [water, setWater] = useState(initialData?.water || 0);
  const [energy, setEnergy] = useState(initialData?.energy || 0);
  const [attachments, setAttachments] = useState<{ name: string; type: string; data: string }[]>(initialData?.attachments || []);
  const [isSaving, setIsSaving] = useState(false);
  const [isCompressing, setIsCompressing] = useState(false);
  const [previousBalance, setPreviousBalance] = useState(initialData?.previousBalance || 0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isCamposBelos = (initialData?.institutionName || session.institution).toLowerCase().replace(/\s+/g, '').includes('camposbelos');

  const compressImage = (base64Str: string): Promise<string> => {
    return new Promise((resolve) => {
      const img = new Image();
      img.src = base64Str;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX_WIDTH = 1200;
        let width = img.width;
        let height = img.height;
        if (width > MAX_WIDTH) { height *= MAX_WIDTH / width; width = MAX_WIDTH; }
        canvas.width = width; canvas.height = height;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL('image/jpeg', 0.6));
      };
    });
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (readOnly) return;
    const files = e.target.files;
    if (!files) return;
    setIsCompressing(true);
    // Fixed: Explicitly cast files to File[] to avoid 'unknown' type errors during file processing.
    for (const file of Array.from(files) as File[]) {
      try {
        const base64: string = await new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          // Fixed: Argument of type 'unknown' is not assignable to parameter of type 'Blob'.
          reader.readAsDataURL(file);
        });
        const compressed = await compressImage(base64);
        // Fixed: Property 'name' does not exist on type 'unknown'.
        setAttachments(prev => [...prev, { name: file.name, type: 'image/jpeg', data: compressed }]);
      } catch (err) { console.error(err); }
    }
    setIsCompressing(false);
  };

  const sumOtherRevenues = otherRevenues.reduce((acc, curr) => acc + (curr.value || 0), 0);
  const totalRevenue = (Number(offers) || 0) + (Number(tithes) || 0) + (Number(financialRevenue) || 0) + (Number(specialOffers) || 0) + sumOtherRevenues;
  const sedeExpense = isCamposBelos ? 0 : totalRevenue * 0.20;
  const prebendaExpense = isCamposBelos ? 0 : totalRevenue * 0.20;
  const revenue60 = isCamposBelos ? totalRevenue : totalRevenue * 0.60;
  const sumOtherExpenses = otherExpenses.reduce((acc, curr) => acc + (curr.value || 0), 0);
  const totalFixedExpenses = (Number(rent) || 0) + (Number(water) || 0) + (Number(energy) || 0) + sumOtherExpenses;
  const totalExpenses = sedeExpense + prebendaExpense + totalFixedExpenses;
  const saldoGU = revenue60 - totalFixedExpenses;
  const currentBalance = previousBalance + saldoGU;

  const formatBRL = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

  const handleSubmit = async () => {
    if (readOnly && session.role !== 'ADMIN') { onFinished(); return; }
    setIsSaving(true);
    const report: FinancialReport = {
      id: initialData?.id || crypto.randomUUID(),
      date, institutionName: initialData?.institutionName || session.institution,
      reporterName: initialData?.reporterName || session.name, userId: initialData?.userId || session.id,
      locked: initialData?.locked || false, offers, tithes, financialRevenue, specialOffers, otherRevenues,
      rent, water, energy, otherExpenses, totalRevenue, totalFixedExpenses, sedeExpense, prebendaExpense,
      totalExpenses, saldoGU, currentBalance, previousBalance, attachments, createdAt: initialData?.createdAt || new Date().toISOString()
    };
    try {
      await saveReport(report);
      onFinished();
    } catch (err: any) { alert("Erro ao salvar relatório."); } finally { setIsSaving(false); }
  };

  return (
    <div className="space-y-8 max-w-4xl mx-auto animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 px-4">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-3 bg-white text-slate-400 rounded-xl shadow-sm"><ArrowLeft size={20}/></button>
          <div>
            <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">{readOnly ? 'Visualização' : 'Novo Fechamento'}</h2>
            <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">{session.institution}</p>
          </div>
        </div>
      </div>

      <div className="flex bg-white p-2 rounded-[1.5rem] shadow-soft border border-slate-50 overflow-x-auto">
        {(['RECEITAS', 'DESPESAS', 'ANEXOS', 'RESUMO'] as FormTab[]).map(tab => (
          <button key={tab} onClick={() => setActiveTab(tab)} className={`flex-1 py-4 px-6 rounded-2xl text-[9px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>{tab}</button>
        ))}
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 p-8 shadow-sm min-h-[400px]">
        {activeTab === 'RECEITAS' && (
          <div className="space-y-6 animate-in slide-in-from-right-4">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Data Referência</label>
                  <input type="date" disabled={readOnly} value={date} onChange={e => setDate(e.target.value)} className="w-full p-4 bg-slate-50 rounded-2xl border border-transparent font-bold text-xs" />
                </div>
                <div className="space-y-1">
                  <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Saldo Anterior</label>
                  <input type="number" disabled={readOnly} value={previousBalance} onChange={e => setPreviousBalance(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl border border-transparent font-black text-xs" />
                </div>
             </div>
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-4">
                <div className="space-y-4">
                   <h4 className="text-[10px] font-black uppercase text-indigo-500 border-b border-indigo-50 pb-2">Entradas</h4>
                   {[
                     { label: 'Dízimos', val: tithes, set: setTithes },
                     { label: 'Ofertas Gerais', val: offers, set: setOffers },
                     { label: 'Ofertas Especiais', val: specialOffers, set: setSpecialOffers },
                     { label: 'Receita Financeira', val: financialRevenue, set: setFinancialRevenue }
                   ].map(item => (
                     <div key={item.label} className="space-y-1">
                        <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">{item.label}</label>
                        <input type="number" disabled={readOnly} value={item.val || ''} onChange={e => item.set(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs" placeholder="0,00" />
                     </div>
                   ))}
                </div>
                <div className="space-y-4">
                   <div className="flex justify-between items-center border-b border-slate-50 pb-2">
                     <h4 className="text-[10px] font-black uppercase text-slate-900">Outras Receitas</h4>
                     {!readOnly && <button onClick={() => setOtherRevenues([...otherRevenues, { id: crypto.randomUUID(), description: '', value: 0 }])} className="p-2 bg-indigo-50 text-indigo-600 rounded-lg"><Plus size={14}/></button>}
                   </div>
                   {otherRevenues.map(item => (
                     <div key={item.id} className="flex gap-2">
                        <input type="text" disabled={readOnly} value={item.description} onChange={e => setOtherRevenues(otherRevenues.map(i => i.id === item.id ? {...i, description: e.target.value} : i))} className="flex-1 p-3 bg-slate-50 rounded-xl text-[10px] font-bold" placeholder="Descrição" />
                        <input type="number" disabled={readOnly} value={item.value || ''} onChange={e => setOtherRevenues(otherRevenues.map(i => i.id === item.id ? {...i, value: Number(e.target.value)} : i))} className="w-24 p-3 bg-slate-50 rounded-xl text-[10px] font-black" placeholder="0,00" />
                        {!readOnly && <button onClick={() => setOtherRevenues(otherRevenues.filter(i => i.id !== item.id))} className="p-2 text-rose-500"><Trash2 size={14}/></button>}
                     </div>
                   ))}
                </div>
             </div>
          </div>
        )}

        {activeTab === 'DESPESAS' && (
          <div className="space-y-6 animate-in slide-in-from-right-4">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-4">
                   <h4 className="text-[10px] font-black uppercase text-rose-500 border-b border-rose-50 pb-2">Despesas Fixas</h4>
                   {[
                     { label: 'Aluguel Unidade', val: rent, set: setRent },
                     { label: 'Energia Elétrica', val: energy, set: setEnergy },
                     { label: 'Água / Saneamento', val: water, set: setWater }
                   ].map(item => (
                     <div key={item.label} className="space-y-1">
                        <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">{item.label}</label>
                        <input type="number" disabled={readOnly} value={item.val || ''} onChange={e => item.set(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs" />
                     </div>
                   ))}
                </div>
                <div className="space-y-4">
                   <div className="flex justify-between items-center border-b border-slate-50 pb-2">
                     <h4 className="text-[10px] font-black uppercase text-slate-900">Outras Despesas</h4>
                     {!readOnly && <button onClick={() => setOtherExpenses([...otherExpenses, { id: crypto.randomUUID(), description: '', value: 0 }])} className="p-2 bg-indigo-50 text-indigo-600 rounded-lg"><Plus size={14}/></button>}
                   </div>
                   {otherExpenses.map(item => (
                     <div key={item.id} className="flex gap-2">
                        <input type="text" disabled={readOnly} value={item.description} onChange={e => setOtherExpenses(otherExpenses.map(i => i.id === item.id ? {...i, description: e.target.value} : i))} className="flex-1 p-3 bg-slate-50 rounded-xl text-[10px] font-bold" />
                        <input type="number" disabled={readOnly} value={item.value || ''} onChange={e => setOtherExpenses(otherExpenses.map(i => i.id === item.id ? {...i, value: Number(e.target.value)} : i))} className="w-24 p-3 bg-slate-50 rounded-xl text-[10px] font-black" />
                        {!readOnly && <button onClick={() => setOtherExpenses(otherExpenses.filter(i => i.id !== item.id))} className="p-2 text-rose-500"><Trash2 size={14}/></button>}
                     </div>
                   ))}
                </div>
             </div>
          </div>
        )}

        {activeTab === 'ANEXOS' && (
          <div className="space-y-6 animate-in slide-in-from-right-4">
             {!readOnly && (
               <div onClick={() => fileInputRef.current?.click()} className="border-2 border-dashed border-slate-200 rounded-[2rem] p-12 text-center hover:border-indigo-300 cursor-pointer group">
                 <UploadCloud size={48} className="mx-auto text-slate-300 group-hover:text-indigo-500 mb-4" />
                 <h4 className="text-xs font-black uppercase">Anexar Comprovantes</h4>
                 <input type="file" ref={fileInputRef} className="hidden" multiple accept="image/*" onChange={handleFileChange} />
               </div>
             )}
             <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {attachments.map((at, idx) => (
                  <div key={idx} className="relative rounded-2xl overflow-hidden aspect-square">
                    <img src={at.data} className="w-full h-full object-cover" />
                    {!readOnly && <button onClick={() => setAttachments(attachments.filter((_, i) => i !== idx))} className="absolute top-2 right-2 p-2 bg-rose-600 text-white rounded-lg"><Trash2 size={14}/></button>}
                  </div>
                ))}
             </div>
          </div>
        )}

        {activeTab === 'RESUMO' && (
          <div className="space-y-8 animate-in slide-in-from-right-4">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-3">
                   <h4 className="text-[10px] font-black uppercase text-slate-900 border-b pb-2">Distribuição</h4>
                   <div className="flex justify-between p-4 bg-slate-50 rounded-2xl">
                      <span className="text-[9px] font-black uppercase text-slate-400">Total Bruto</span>
                      <span className="text-[10px] font-black">{formatBRL(totalRevenue)}</span>
                   </div>
                   <div className="flex justify-between p-4 bg-emerald-50 rounded-2xl">
                      <span className="text-[9px] font-black uppercase text-emerald-500">Saldo GU ({isCamposBelos ? '100%' : '60%'})</span>
                      <span className="text-[10px] font-black text-emerald-600">{formatBRL(revenue60)}</span>
                   </div>
                </div>
                <div className="space-y-3">
                   <h4 className="text-[10px] font-black uppercase text-slate-900 border-b pb-2">Resultado Final</h4>
                   <div className="flex justify-between p-4 bg-slate-950 rounded-[2rem] text-white">
                      <span className="text-[10px] font-black uppercase">Saldo Líquido</span>
                      <span className="text-sm font-black text-emerald-400">{formatBRL(saldoGU)}</span>
                   </div>
                   <div className="flex justify-between p-4 bg-slate-50 rounded-2xl border">
                      <span className="text-[9px] font-black uppercase text-slate-400">Caixa Geral</span>
                      <span className="text-[10px] font-black">{formatBRL(currentBalance)}</span>
                   </div>
                </div>
             </div>
          </div>
        )}
      </div>

      <div className="flex gap-4">
        {activeTab !== 'RESUMO' ? (
          <button onClick={() => { const tabs: FormTab[] = ['RECEITAS', 'DESPESAS', 'ANEXOS', 'RESUMO']; const idx = tabs.indexOf(activeTab); setActiveTab(tabs[idx + 1]); }} className="flex-1 py-5 bg-slate-900 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 active-scale">Próxima Etapa <ArrowRight size={18}/></button>
        ) : (
          <button onClick={handleSubmit} disabled={isSaving} className="flex-1 py-5 bg-indigo-600 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 active-scale shadow-xl shadow-indigo-100">
