    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { ReportForm } from './components/ReportForm';
import { ReportHistory } from './components/ReportHistory';
import { AdminDashboard } from './components/AdminDashboard';
import { UserManagement } from './components/UserManagement';
import { TrashManager } from './components/TrashManager';
import { Settings } from './components/Settings';
import { Logo } from './components/Logo';
import { UserSession, FinancialReport } from './types';
import { getUserByUsername } from './services/storageService';
import { Lock, UserCircle, ArrowRight, RefreshCw, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [session, setSession] = useState<UserSession | null>(null);
  const [currentView, setCurrentView] = useState<'REPORT_NEW' | 'HISTORY' | 'DASHBOARD' | 'USERS' | 'TRASH' | 'SETTINGS'>('HISTORY');
  const [editingReport, setEditingReport] = useState<FinancialReport | null>(null);
  const [isReadOnly, setIsReadOnly] = useState(false);
  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');
  const [isLoggingIn, setIsLoggingIn] = useState(false);

  const handleLoginSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const userLower = loginUsername.toLowerCase().trim();
    const passRaw = loginPassword.trim();

    if (!userLower || !passRaw) {
      setLoginError('Informe usuário e senha');
      return;
    }

    setLoginError('');
    setIsLoggingIn(true);

    if (userLower === 'adm' && passRaw === 'adm') {
      setSession({
        id: 'admin-master',
        name: 'Administrador Geral',
        role: 'ADMIN',
        institution: 'Sede Administrativa'
      });
      setCurrentView('DASHBOARD');
      setIsLoggingIn(false);
      return;
    }

    try {
      const user = await getUserByUsername(userLower);
      if (!user) {
        setLoginError('Usuário não encontrado');
        setIsLoggingIn(false);
        return;
      }
      if (user.password !== passRaw) {
        setLoginError('Senha incorreta');
        setIsLoggingIn(false);
        return;
      }

      setSession({ 
        id: user.id, 
        name: user.name, 
        phone: user.phone,
        photo: user.photo,
        role: user.role, 
        institution: user.institution.trim()
      });

      setCurrentView(user.role === 'ADMIN' ? 'DASHBOARD' : 'HISTORY');
    } catch (err: any) {
      setLoginError('Erro de conexão');
    } finally {
      setIsLoggingIn(false);
    }
  };

  const handleOpenReport = (report: FinancialReport, readOnly: boolean = false) => {
    setEditingReport(report);
    setIsReadOnly(readOnly);
    setCurrentView('REPORT_NEW');
  };

  const renderContent = () => {
    if (!session) return null;
    switch (currentView) {
      case 'DASHBOARD': return <AdminDashboard session={session} />;
      case 'REPORT_NEW': return (
        <ReportForm 
          session={session} 
          initialData={editingReport || undefined}
          readOnly={isReadOnly}
          onFinished={() => { setEditingReport(null); setIsReadOnly(false); setCurrentView('HISTORY'); }} 
          onCancel={() => { setEditingReport(null); setIsReadOnly(false); setCurrentView('HISTORY'); }} 
        />
      );
      case 'HISTORY': return (
        <ReportHistory 
          session={session} 
          onEdit={(rep, ro) => handleOpenReport(rep, ro)}
          onBack={() => setCurrentView('HISTORY')} 
          onGoToTrash={() => setCurrentView('TRASH')}
        />
      );
      case 'USERS': return <UserManagement session={session} />;
      case 'TRASH': return <TrashManager session={session} />;
      case 'SETTINGS': return <Settings />;
      default: return <ReportHistory session={session} onEdit={handleOpenReport} onBack={() => setCurrentView('HISTORY')} onGoToTrash={() => setCurrentView('TRASH')} />;
    }
  };

  if (!session) {
    return (
      <div className="min-h-screen flex items-center justify-center p-5 mesh-bg">
        <div className="max-w-xs w-full">
          <div className="bg-white/90 backdrop-blur-3xl p-8 rounded-[2.5rem] shadow-3xl border border-white flex flex-col items-center">
            <div className="mb-8 p-3 bg-indigo-600 rounded-2xl">
              <Logo size="sm" className="brightness-0 invert w-6 h-6" />
            </div>
            <h1 className="text-xl font-black text-slate-900 uppercase">Portal ADGU</h1>
            <form onSubmit={handleLoginSubmit} className="space-y-4 w-full mt-8">
              <input type="text" value={loginUsername} onChange={e => setLoginUsername(e.target.value)} className="w-full px-4 py-3.5 rounded-xl bg-slate-50 border outline-none font-bold text-xs" placeholder="Usuário" />
              <input type="password" value={loginPassword} onChange={e => setLoginPassword(e.target.value)} className="w-full px-4 py-3.5 rounded-xl bg-slate-50 border outline-none font-bold text-xs" placeholder="Senha" />
              {loginError && <p className="text-rose-600 text-[10px] font-black uppercase text-center">{loginError}</p>}
              <button type="submit" disabled={isLoggingIn} className="w-full bg-slate-900 text-white font-black py-4 rounded-xl flex items-center justify-center gap-2 uppercase text-[9px]">
                {isLoggingIn ? <RefreshCw className="animate-spin" size={14} /> : 'Acessar'} <ArrowRight size={14} />
              </button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout session={session} currentView={currentView} onViewChange={setCurrentView} onLogout={() => { setSession(null); setCurrentView('HISTORY'); }}>
      {renderContent()}
    </Layout>
  );
};

export default App;

