import React, { useState, useEffect } from 'react';
import { FinancialReport, UserSession } from '../types';
import { getReports, getSettings, isCompetenceLocked } from '../services/storageService';
import { Calendar, Search, RefreshCw, ImageIcon, X, Send, Eye } from 'lucide-react';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface ReportHistoryProps {
  session: UserSession;
  onBack: () => void;
  onEdit?: (report: FinancialReport, readOnly?: boolean) => void;
  onGoToTrash?: () => void;
}

export const ReportHistory: React.FC<ReportHistoryProps> = ({ session, onBack, onEdit, onGoToTrash }) => {
  const [reports, setReports] = useState<FinancialReport[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [closingDay, setClosingDay] = useState(1);
  const [viewingPhotos, setViewingPhotos] = useState<FinancialReport | null>(null);

  const fetchReports = async () => {
    try {
      setLoading(true);
      const settings = await getSettings();
      setClosingDay(settings.closingDay || 1);
      const allReports = await getReports();
      const filtered = allReports.filter(r => session.role === 'ADMIN' || r.institutionName.toLowerCase() === session.institution.toLowerCase());
      setReports(filtered);
    } catch (err) { console.error(err); } finally { setLoading(false); }
  };

  useEffect(() => {
    fetchReports();
  }, []);

  const formatBRL = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

  const generatePDF = async (report: FinancialReport) => {
    const settings = await getSettings();
    const doc = new jsPDF() as any;
    const pageWidth = doc.internal.pageSize.getWidth();
    let currentY = 20;

    // Cabeçalho
    if (settings.logo) {
      doc.addImage(settings.logo, 'PNG', 15, currentY, 25, 25);
    }
    doc.setFontSize(14); doc.setFont("helvetica", "bold"); doc.setTextColor(30, 41, 59);
    doc.text(settings.institutionName.toUpperCase(), settings.logo ? 45 : 15, currentY + 10);
    doc.setFontSize(8); doc.setFont("helvetica", "normal"); doc.setTextColor(100, 116, 139);
    doc.text(`Relatório Gerado em: ${new Date().toLocaleDateString('pt-BR')}`, settings.logo ? 45 : 15, currentY + 16);
    currentY += 35;

    // Resumo Geral
    doc.setFontSize(10); doc.setFont("helvetica", "bold"); doc.setTextColor(30, 41, 59);
    doc.text(`Unidade: ${report.institutionName}`, 15, currentY);
    doc.text(`Competência: ${report.date.split('-').reverse().join('/')}`, pageWidth - 15, currentY, { align: 'right' });
    currentY += 10;

    // Tabela de Entradas
    doc.autoTable({
      startY: currentY,
      head: [['Descritivo de Entradas (100%)', 'Valor']],
      body: [
        ['Dízimos', formatBRL(report.tithes)],
        ['Ofertas Gerais', formatBRL(report.offers)],
        ['Ofertas Especiais', formatBRL(report.specialOffers)],
        ['Receita Financeira', formatBRL(report.financialRevenue)],
        ...report.otherRevenues.map(r => [r.description || 'Outras Entradas', formatBRL(r.value)]),
        [{ content: 'TOTAL BRUTO', styles: { fontStyle: 'bold', fillColor: [241, 245, 249] } }, { content: formatBRL(report.totalRevenue), styles: { fontStyle: 'bold', halign: 'right', fillColor: [241, 245, 249] } }]
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
      columnStyles: { 1: { halign: 'right' } }
    });

    currentY = doc.lastAutoTable.finalY + 10;

    // Tabela de Repasses e Saídas
    doc.autoTable({
      startY: currentY,
      head: [['Repasses Obrigatórios e Despesas Unidade', 'Valor']],
      body: [
        ['Repasse Sede (20%)', formatBRL(report.sedeExpense)],
        ['Prebenda Pastoral (20%)', formatBRL(report.prebendaExpense)],
        ['Aluguel', formatBRL(report.rent)],
        ['Energia Elétrica', formatBRL(report.energy)],
        ['Água / Saneamento', formatBRL(report.water)],
        ...report.otherExpenses.map(e => [e.description || 'Outras Despesas', formatBRL(e.value)]),
        [{ content: 'TOTAL DE SAÍDAS', styles: { fontStyle: 'bold', fillColor: [254, 242, 242] } }, { content: formatBRL(report.totalExpenses), styles: { fontStyle: 'bold', halign: 'right', fillColor: [254, 242, 242] } }]
      ],
      theme: 'grid',
      headStyles: { fillColor: [244, 63, 94] },
      columnStyles: { 1: { halign: 'right' } }
    });

    currentY = doc.lastAutoTable.finalY + 15;

    // Quadro de Saldo
    doc.setFillColor(15, 23, 42);
    doc.roundedRect(15, currentY, pageWidth - 30, 20, 3, 3, 'F');
    doc.setFontSize(12); doc.setTextColor(255, 255, 255);
    doc.text("SALDO LÍQUIDO DISPONÍVEL (GU):", 22, currentY + 12);
    doc.text(formatBRL(report.saldoGU), pageWidth - 22, currentY + 12, { align: 'right' });

    doc.save(`ADGU_Relatorio_${report.institutionName}_${report.date}.pdf`);
  };

  const shareWhatsApp = async (report: FinancialReport) => {
    await generatePDF(report);
    const phone = "5585920003598";
    const message = `*RELATÓRIO FINANCEIRO ADGU*%0A%0A` +
      `*Unidade:* ${report.institutionName}%0A` +
      `*Data:* ${report.date.split('-').reverse().join('/')}%0A%0A` +
      `*ENTRADAS (100%):*%0A` +
      `- Bruto: ${formatBRL(report.totalRevenue)}%0A%0A` +
      `*REPASSES (40%):*%0A` +
      `- Sede (20%): ${formatBRL(report.sedeExpense)}%0A` +
      `- Prebenda (20%): ${formatBRL(report.prebendaExpense)}%0A%0A` +
      `*DISPONÍVEL UNIDADE (60%):*%0A` +
      `- Valor: ${formatBRL(report.totalRevenue * 0.6)}%0A` +
      `- Despesas Pagas: ${formatBRL(report.totalFixedExpenses)}%0A%0A` +
      `*SALDO FINAL GU:*%0A` +
      `👉 *${formatBRL(report.saldoGU)}*%0A%0A` +
      `_O arquivo PDF foi gerado para anexo._`;

    window.open(`https://wa.me/${phone}?text=${message}`, '_blank');
  };

  const filtered = reports.filter(r => r.institutionName.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div className="space-y-6">
      <div className="bg-white p-4 rounded-3xl border flex items-center gap-4">
        <Search size={18} className="text-slate-300" />
        <input type="text" placeholder="Buscar unidade..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="flex-1 outline-none text-xs font-bold" />
      </div>

      <div className="grid gap-3">
        {loading ? (
          <RefreshCw className="animate-spin mx-auto text-indigo-500" />
        ) : filtered.map(report => (
          <div key={report.id} className="bg-white p-5 rounded-3xl border flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Calendar className="text-indigo-500" size={24} />
              <div>
                <h4 className="text-xs font-black uppercase text-slate-900">{report.date.split('-').reverse().join('/')}</h4>
                <p className="text-[8px] font-black text-indigo-500 uppercase">{report.institutionName}</p>
                <p className="text-[10px] font-black text-emerald-600 mt-1">{formatBRL(report.saldoGU)}</p>
              </div>
            </div>
            <div className="flex gap-2">
              <button onClick={() => onEdit?.(report, true)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl"><Eye size={18}/></button>
              <button onClick={() => shareWhatsApp(report)} className="p-3 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center gap-2">
                <Send size={18} />
                <span className="text-[8px] font-black uppercase">Enviar</span>
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

