                        <span className="text-[10px] font-black text-emerald-700">{formatBRL(revenue60)}</span>
                     </div>
                   </div>
                </div>
                <div className="space-y-4">
                   <h4 className="text-[10px] font-black uppercase text-slate-900 border-b border-slate-100 pb-2">Resultado Final Unidade</h4>
