}

export const ReportHistory: React.FC<ReportHistoryProps> = ({ session, onBack, onEdit, onGoToTrash }) => {
  const [reports, setReports] = useState<FinancialReport[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [closingDay, setClosingDay] = useState(1);
  const [viewingPhotos, setViewingPhotos] = useState<FinancialReport | null>(null);

  const fetchReports = async () => {
    try {
      setLoading(true);
      const settings = await getSettings();
      setClosingDay(settings.closingDay || 1);
      const allReports = await getReports();
      const filtered = allReports.filter(r => session.role === 'ADMIN' || r.institutionName.toLowerCase() === session.institution.toLowerCase());
      setReports(filtered);
    } catch (err) { console.error(err); } finally { setLoading(false); }
  };

  useEffect(() => {
    fetchReports();
  }, []);

  const formatBRL = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

  const generatePDF = async (report: FinancialReport) => {
    const settings = await getSettings();
    const doc = new jsPDF() as any;
    const pageWidth = doc.internal.pageSize.getWidth();
    let currentY = 20;

    // Cabeçalho Profissional
    if (settings.logo) {
      try {
        doc.addImage(settings.logo, 'PNG', 15, currentY, 25, 25);
      } catch (e) { console.warn("Erro ao carregar logo no PDF"); }
    }

    doc.setFontSize(14); doc.setFont("helvetica", "bold"); doc.setTextColor(30, 41, 59);
    doc.text(settings.institutionName.toUpperCase(), settings.logo ? 45 : 15, currentY + 10);
    doc.setFontSize(8); doc.setFont("helvetica", "normal"); doc.setTextColor(100, 116, 139);
    doc.text(`CNPJ: ${settings.cnpj}`, settings.logo ? 45 : 15, currentY + 16);
    doc.text(`Relatório Gerado em: ${new Date().toLocaleDateString('pt-BR')} ${new Date().toLocaleTimeString('pt-BR')}`, settings.logo ? 45 : 15, currentY + 21);
    currentY += 40;

    // Título do Relatório
    doc.setFillColor(79, 70, 229);
    doc.roundedRect(15, currentY, pageWidth - 30, 12, 2, 2, 'F');
    doc.setFontSize(10); doc.setTextColor(255, 255, 255); doc.setFont("helvetica", "bold");
    doc.text(`FECHAMENTO SEMANAL: ${report.institutionName.toUpperCase()}`, 20, currentY + 8);
    doc.text(`REF: ${report.date.split('-').reverse().join('/')}`, pageWidth - 20, currentY + 8, { align: 'right' });
    currentY += 20;

    // Seção de Receitas
    doc.setFontSize(11); doc.setTextColor(30, 41, 59);
    doc.text("ENTRADAS BRUTAS (100%)", 15, currentY);
    currentY += 5;

    doc.autoTable({
      startY: currentY,
      head: [['Descritivo', 'Valor']],
      body: [
        ['Dízimos', formatBRL(report.tithes)],
        ['Ofertas Gerais', formatBRL(report.offers)],
        ['Ofertas Especiais', formatBRL(report.specialOffers)],
        ['Receita Financeira', formatBRL(report.financialRevenue)],
        ...report.otherRevenues.map(r => [r.description || 'Outra Receita', formatBRL(r.value)]),
        [{ content: 'TOTAL BRUTO DO PERÍODO', styles: { fontStyle: 'bold', fillColor: [241, 245, 249] } }, { content: formatBRL(report.totalRevenue), styles: { fontStyle: 'bold', halign: 'right', fillColor: [241, 245, 249] } }]
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
      columnStyles: { 1: { halign: 'right' } }
    });

    currentY = doc.lastAutoTable.finalY + 10;

    // Seção de Repasses (Porcentagens)
    doc.setFontSize(11);
    doc.text("REPASSES OBRIGATÓRIOS (40%)", 15, currentY);
    currentY += 5;

    doc.autoTable({
      startY: currentY,
      head: [['Categoria de Repasse', 'Porcentagem', 'Valor']],
      body: [
        ['Sede Administrativa', '20%', formatBRL(report.sedeExpense)],
        ['Prebenda Pastoral', '20%', formatBRL(report.prebendaExpense)],
        [{ content: 'TOTAL DE REPASSES', styles: { fontStyle: 'bold', fillColor: [255, 251, 235] } }, { content: '40%', styles: { fontStyle: 'bold', fillColor: [255, 251, 235] } }, { content: formatBRL(report.sedeExpense + report.prebendaExpense), styles: { fontStyle: 'bold', halign: 'right', fillColor: [255, 251, 235] } }]
      ],
      theme: 'grid',
      headStyles: { fillColor: [245, 158, 11] },
      columnStyles: { 2: { halign: 'right' } }
    });

    currentY = doc.lastAutoTable.finalY + 10;

    // Seção de Despesas Unidade
    doc.setFontSize(11);
    doc.text("DESPESAS DA UNIDADE (60%)", 15, currentY);
    currentY += 5;

    doc.autoTable({
      startY: currentY,
      head: [['Despesa Unidade', 'Valor']],
      body: [
        ['Disponível para a Unidade (60% do Bruto)', formatBRL(report.totalRevenue * 0.6)],
        ['Aluguel', formatBRL(report.rent)],
        ['Energia Elétrica', formatBRL(report.energy)],
        ['Água / Saneamento', formatBRL(report.water)],
        ...report.otherExpenses.map(e => [e.description || 'Despesa Extra', formatBRL(e.value)]),
        [{ content: 'TOTAL DE CUSTOS OPERACIONAIS', styles: { fontStyle: 'bold', fillColor: [254, 242, 242] } }, { content: formatBRL(report.totalFixedExpenses), styles: { fontStyle: 'bold', halign: 'right', fillColor: [254, 242, 242] } }]
      ],
      theme: 'grid',
      headStyles: { fillColor: [244, 63, 94] },
      columnStyles: { 1: { halign: 'right' } }
    });

    currentY = doc.lastAutoTable.finalY + 15;

    // Quadro de Saldo Consolidado
    doc.setFillColor(15, 23, 42);
    doc.roundedRect(15, currentY, pageWidth - 30, 20, 3, 3, 'F');
    doc.setFontSize(12); doc.setTextColor(255, 255, 255); doc.setFont("helvetica", "bold");
    doc.text("SALDO LÍQUIDO FINAL GU:", 22, currentY + 12);
    doc.text(formatBRL(report.saldoGU), pageWidth - 22, currentY + 12, { align: 'right' });

    currentY += 30;
    doc.setFontSize(8); doc.setTextColor(100, 116, 139); doc.setFont("helvetica", "normal");
    doc.text("__________________________________________", 15, currentY);
    doc.text("Assinatura do Responsável (Tesoureiro)", 15, currentY + 5);

    doc.text("__________________________________________", pageWidth - 15, currentY, { align: 'right' });
    doc.text("Assinatura do Pastor / Dirigente", pageWidth - 15, currentY + 5, { align: 'right' });

    doc.save(`ADGU_Relatorio_${report.institutionName.replace(/\s+/g, '_')}_${report.date}.pdf`);
  };

  const shareWhatsApp = async (report: FinancialReport) => {
    // Gerar o PDF primeiro para download automático
    await generatePDF(report);

    const phone = "5585920003598";
    const message = `*RELATÓRIO FINANCEIRO ADGU*%0A%0A` +
      `📌 *Unidade:* ${report.institutionName}%0A` +
      `📅 *Referência:* ${report.date.split('-').reverse().join('/')}%0A` +
      `👤 *Responsável:* ${report.reporterName}%0A%0A` +
      `💰 *ENTRADAS (100%):*%0A` +
      `- Receita Bruta: *${formatBRL(report.totalRevenue)}*%0A%0A` +
      `🏛️ *REPASSES (40%):*%0A` +
      `- Sede (20%): ${formatBRL(report.sedeExpense)}%0A` +
      `- Prebenda (20%): ${formatBRL(report.prebendaExpense)}%0A%0A` +
      `🏠 *UNIDADE (60%):*%0A` +
      `- Disponível GU: ${formatBRL(report.totalRevenue * 0.6)}%0A` +
      `- Gastos Unidade: ${formatBRL(report.totalFixedExpenses)}%0A%0A` +
      `✅ *SALDO LÍQUIDO FINAL:*%0A` +
      `👉 *${formatBRL(report.saldoGU)}*%0A%0A` +
      `_O arquivo PDF detalhado foi gerado e baixado no seu dispositivo para anexo._`;

    window.open(`https://wa.me/${phone}?text=${message}`, '_blank');
  };

  const filtered = reports.filter(r => r.institutionName.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      <div className="bg-white p-5 rounded-[2rem] border border-slate-100 shadow-soft flex gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
          <input 
            type="text" 
            placeholder="Buscar por unidade ou data..." 
            value={searchTerm} 
            onChange={e => setSearchTerm(e.target.value)} 
            className="w-full pl-12 pr-4 py-3.5 bg-slate-50 rounded-2xl border border-transparent outline-none font-bold text-xs focus:bg-white focus:border-indigo-100 transition-all" 
          />
        </div>
      </div>

      <div className="grid gap-3">
        {loading ? (
          <div className="py-20 flex flex-col items-center justify-center gap-4">
            <RefreshCw className="animate-spin text-indigo-500" size={32} />
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Buscando Relatórios...</p>
          </div>
        ) : filtered.length === 0 ? (
          <div className="py-20 text-center bg-white rounded-[2rem] border border-dashed border-slate-200">
            <FileDown size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nenhum relatório encontrado</p>
          </div>
        ) : (
          filtered.map(report => (
            <div key={report.id} className="bg-white p-5 rounded-3xl border border-slate-50 shadow-sm flex items-center justify-between group hover:border-indigo-100 transition-all">
              <div className="flex items-center gap-4">
                <div className="p-3 bg-indigo-50 text-indigo-500 rounded-2xl group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                  <Calendar size={24} />
                </div>
                <div>
                  <h4 className="text-xs font-black uppercase text-slate-900 tracking-tight">{report.date.split('-').reverse().join('/')}</h4>
                  <p className="text-[8px] font-black text-indigo-500 uppercase tracking-widest">{report.institutionName}</p>
                  <p className="text-[10px] font-black text-emerald-600 mt-1">{formatBRL(report.saldoGU)}</p>
                </div>
              </div>
              <div className="flex gap-2">
                {report.attachments?.length > 0 && (
                  <button onClick={() => setViewingPhotos(report)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-slate-100 transition-colors" title="Ver Anexos">
                    <ImageIcon size={18}/>
                  </button>
                )}
                <button onClick={() => onEdit?.(report, true)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-slate-100 transition-colors" title="Visualizar Detalhes">
                  <Eye size={18}/>
                </button>
                <button onClick={() => shareWhatsApp(report)} className="p-3 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center gap-2 hover:bg-emerald-600 hover:text-white transition-all active-scale shadow-sm">
                  <Send size={18} />
                  <span className="hidden sm:inline text-[8px] font-black uppercase tracking-widest">Enviar</span>
                </button>
              </div>
            </div>
          ))
        )}
      </div>

      {viewingPhotos && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 animate-in fade-in duration-300">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-md" onClick={() => setViewingPhotos(null)} />
          <div className="relative w-full max-w-4xl bg-white rounded-[2.5rem] p-8 shadow-3xl flex flex-col max-h-[90vh]">
             <div className="flex justify-between items-center mb-6 px-4">
                <div>
                  <h3 className="text-lg font-black text-slate-900 uppercase tracking-tight">Anexos do Relatório</h3>
                  <p className="text-[8px] font-black text-indigo-500 uppercase tracking-widest">{viewingPhotos.institutionName} - {viewingPhotos.date.split('-').reverse().join('/')}</p>
                </div>
                <button onClick={() => setViewingPhotos(null)} className="p-2 bg-slate-100 rounded-xl text-slate-400 hover:text-slate-900 transition-colors"><X size={24}/></button>
             </div>
             <div className="flex-1 overflow-y-auto grid grid-cols-1 sm:grid-cols-2 gap-4 p-4 no-scrollbar">
                {viewingPhotos.attachments.map((file, idx) => (
                  <div key={idx} className="relative rounded-3xl overflow-hidden border bg-slate-50 shadow-sm group">
                    <img src={file.data} className="w-full h-64 object-cover" />
                    <button onClick={() => { const l=document.createElement('a'); l.href=file.data; l.download=`anexo_${idx}.jpg`; l.click(); }} className="absolute bottom-4 right-4 p-3 bg-white/90 backdrop-blur-sm text-slate-900 rounded-xl shadow-lg opacity-0 group-hover:opacity-100 transition-opacity">
                      <Download size={16}/>
                    </button>
                  </div>
                ))}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export interface MiscItem {
  id: string;
  description: string;
  value: number;
}

export interface FinancialReport {
  id: string;
  date: string;
  institutionName: string;
  reporterName: string;
  userId: string;
  locked: boolean;

  // Revenues
  offers: number;
  specialOffers: number;
  tithes: number;
  financialRevenue: number;
  otherRevenues: MiscItem[];

  // Expenses
  energy: number;
  water: number; 
  rent: number;
  otherExpenses: MiscItem[];

  // Calculated Fields
  totalRevenue: number;
  totalFixedExpenses: number;
  sedeExpense: number; 
  prebendaExpense: number; 
  totalExpenses: number;
  saldoGU: number; 
  currentBalance: number;
  previousBalance: number;

  attachments: { name: string; type: string; data: string }[];
  createdAt: string;
  deletedAt?: string;
  deletedBy?: string;
}

export type UserRole = 'ADMIN' | 'USER';

export interface UserAccount {
  id: string;
  username: string;
  password: string;
  name: string;
  phone?: string;
  photo?: string;
  role: UserRole;
  institution: string;
  active: boolean;
}

export interface UserSession {
  id: string;
  name: string;
  phone?: string;
  photo?: string;
  role: UserRole;
  institution: string;
}

import { FinancialReport, UserAccount } from '../types';
import { supabase } from './supabaseClient';

export interface SystemSettings {
  logo?: string;
  institutionName: string;
  cnpj: string;
  address: string;
  email: string;
  president: string;
  closingDay: number;
}

const notifyUpdate = (event: string) => {
  window.dispatchEvent(new Event(event));
};

const safeNum = (val: any): number => {
  const n = Number(val);
  return isNaN(n) ? 0 : n;
};

export const getUserByUsername = async (username: string): Promise<UserAccount | null> => {
  const userClean = username.toLowerCase().trim();
  try {
    const { data, error } = await supabase
      .from('users')
      .select('*')
      .eq('username', userClean)
      .maybeSingle();

    if (error || !data) return null;

    return {
      id: data.id,
      username: data.username,
      password: data.password,
      name: data.name,
      phone: data.phone,
      photo: data.photo,
      role: data.role as any,
      institution: data.institution || '', 
      active: data.active ?? true
    };
  } catch {
    return null;
  }
};

export const getSettings = async (): Promise<SystemSettings> => {
  try {
    const { data, error } = await supabase.from('settings').select('*').eq('id', 1).single();
    if (error || !data) throw error;
    return {
      institutionName: data.institutionname,
      cnpj: data.cnpj,
      address: data.address,
      email: data.email,
      president: data.president,
      logo: data.logo,
      closingDay: data.closingday || 1
    };
  } catch {
    return { 
      institutionName: 'Assembleia de Deus Geração Unida',
      cnpj: '49.386.673/0001-10',
      address: 'Rua Doze de Outubro 779, Parque Tijuca, Maracanaú - CE',
      email: 'ADGUgeracaounida@gmail.com',
      president: 'Pr. Presidente Antônio Chaves Crus',
      closingDay: 1 
    };
  }
};

export const saveSettings = async (settings: SystemSettings) => {
  const { error } = await supabase.from('settings').upsert({
    id: 1,
    institutionname: settings.institutionName,
    cnpj: settings.cnpj,
    address: settings.address,
    email: settings.email,
    president: settings.president,
    logo: settings.logo,
    closingday: settings.closingDay
  });
  if (error) throw error;
  notifyUpdate('settings-updated');
};

export const getReports = async (institution?: string, includeDeleted = false): Promise<FinancialReport[]> => {
  try {
    let query = supabase.from('reports').select('*');
    if (institution) query = query.eq('institutionname', institution);

    if (includeDeleted) query = query.not('deletedat', 'is', null);
    else query = query.is('deletedat', null);

    const { data, error } = await query.order('date', { ascending: false });
    if (error) throw error;

    return (data || []).map(r => ({
      id: r.id,
      date: r.date,
      institutionName: r.institutionname,
      reporterName: r.reportername,
      userId: r.userid,
      locked: r.locked,
      offers: safeNum(r.offers),
      specialOffers: safeNum(r.specialoffers),
      tithes: safeNum(r.tithes),
      financialRevenue: safeNum(r.financialrevenue),
      otherRevenues: r.otherrevenues || [],
      energy: safeNum(r.energy),
      water: safeNum(r.water),
      rent: safeNum(r.rent),
      otherExpenses: r.otherexpenses || [],
      totalRevenue: safeNum(r.totalrevenue),
      totalFixedExpenses: safeNum(r.totalfixedexpenses),
      sedeExpense: safeNum(r.sedeexpense),
      prebendaExpense: safeNum(r.prebendaexpense),
      totalExpenses: safeNum(r.totalexpenses),
      saldoGU: safeNum(r.saldogu),
      currentBalance: safeNum(r.currentbalance),
      previousBalance: safeNum(r.previousbalance),
      attachments: r.attachments || [],
      createdAt: r.createdat,
      deletedAt: r.deletedat,
      deletedBy: r.deletedby
    }));
  } catch (err) { 
    console.error("Erro ao buscar relatórios:", err);
    return []; 
  }
};

export const saveReport = async (report: FinancialReport) => {
  // Garantir que todos os valores numéricos sejam de fato números antes de enviar
  const reportData = {
    id: report.id,
    date: report.date,
    institutionname: report.institutionName,
    reportername: report.reporterName,
    userid: report.userId,
    locked: !!report.locked,
    offers: safeNum(report.offers),
    specialoffers: safeNum(report.specialOffers),
    tithes: safeNum(report.tithes),
    financialrevenue: safeNum(report.financialRevenue),
    otherrevenues: report.otherRevenues,
    energy: safeNum(report.energy),
    water: safeNum(report.water),
    rent: safeNum(report.rent),
    otherexpenses: report.otherExpenses,
    totalrevenue: safeNum(report.totalRevenue),
    totalfixedexpenses: safeNum(report.totalFixedExpenses),
    sedeexpense: safeNum(report.sedeExpense),
    prebendaexpense: safeNum(report.prebendaExpense),
    totalexpenses: safeNum(report.totalExpenses),
    saldogu: safeNum(report.saldoGU),
    currentbalance: safeNum(report.currentBalance),
    previousbalance: safeNum(report.previousBalance),
    attachments: report.attachments || [],
    createdat: report.createdAt || new Date().toISOString()
  };

  const { error } = await supabase.from('reports').upsert(reportData);
  if (error) {
    console.error("Erro detalhado ao salvar relatório:", error);
    throw error;
  }
  notifyUpdate('reports-updated');
};

export const getUsers = async (): Promise<UserAccount[]> => {
  try {
    const { data, error } = await supabase.from('users').select('*').order('name', { ascending: true });
    if (error) throw error;
    return (data || []).map(u => ({
      id: u.id,
      username: u.username,
      password: u.password,
      name: u.name,
      phone: u.phone,
      photo: u.photo,
      role: u.role as any,
      institution: u.institution,
      active: u.active
    }));
  } catch {
    return [];
  }
};

export const saveUser = async (user: Partial<UserAccount>) => {
  const { error } = await supabase.from('users').upsert({
    id: user.id || crypto.randomUUID(),
    username: user.username,
    password: user.password,
    name: user.name,
    phone: user.phone || '',
    photo: user.photo || '',
    role: user.role || 'USER',
    institution: user.institution,
    active: user.active ?? true
  });
  if (error) throw error;
  notifyUpdate('users-updated');
};

export const updateUserStatus = async (id: string, active: boolean) => {
  await supabase.from('users').update({ active }).eq('id', id);
  notifyUpdate('users-updated');
};

export const softDeleteReport = async (id: string, userName: string) => {
  await supabase.from('reports').update({ deletedat: new Date().toISOString(), deletedby: userName }).eq('id', id);
  notifyUpdate('reports-updated');
};

export const restoreReport = async (id: string) => {
  await supabase.from('reports').update({ deletedat: null, deletedby: null }).eq('id', id);
  notifyUpdate('reports-updated');
};

export const deleteReportPermanently = async (id: string) => {
  await supabase.from('reports').delete().eq('id', id);
  notifyUpdate('reports-updated');
};

export const toggleReportLock = async (id: string, locked: boolean) => {
  await supabase.from('reports').update({ locked }).eq('id', id);
  notifyUpdate('reports-updated');
};

