                          <input type="number" disabled={readOnly} value={item.value || ''} onChange={e => setOtherRevenues(otherRevenues.map(i => i.id === item.id ? {...i, value: Number(e.target.value)} : i))} className="w-24 p-3 bg-slate-50 rounded-xl text-[10px] font-black outline-none focus:bg-white focus:border-indigo-100 transition-all" placeholder="0,00" />
                          {!readOnly && <button onClick={() => setOtherRevenues(otherRevenues.filter(i => i.id !== item.id))} className="p-2 text-rose-500 hover:bg-rose-50 rounded-lg transition-colors"><Trash2 size={14}/></button>}
                      </div>
                    ))}
                   </div>
                </div>
             </div>
          </div>
        )}

        {activeTab === 'DESPESAS' && (
          <div className="space-y-6 animate-in slide-in-from-right-4">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-4">
                   <h4 className="text-[10px] font-black uppercase text-rose-500 border-b border-rose-50 pb-2">Despesas Fixas Unidade</h4>
                   {[
                     { label: 'Aluguel Unidade', val: rent, set: setRent },
