                     {!readOnly && <button onClick={() => setOtherExpenses([...otherExpenses, { id: crypto.randomUUID(), description: '', value: 0 }])} className="p-2 bg-rose-50 text-rose-600 rounded-lg active-scale"><Plus size={14}/></button>}
                   </div>
                   <div className="space-y-2">
                    {otherExpenses.map(item => (
                      <div key={item.id} className="flex gap-2 animate-in slide-in-from-top-2">
                          <input type="text" disabled={readOnly} value={item.description} onChange={e => setOtherExpenses(otherExpenses.map(i => i.id === item.id ? {...i, description: e.target.value} : i))} className="flex-1 p-3 bg-slate-50 rounded-xl text-[10px] font-bold outline-none focus:bg-white focus:border-rose-100 transition-all" />
                          <input type="number" disabled={readOnly} value={item.value || ''} onChange={e => setOtherExpenses(otherExpenses.map(i => i.id === item.id ? {...i, value: Number(e.target.value)} : i))} className="w-24 p-3 bg-slate-50 rounded-xl text-[10px] font-black outline-none focus:bg-white focus:border-rose-100 transition-all" placeholder="0,00" />
                          {!readOnly && <button onClick={() => setOtherExpenses(otherExpenses.filter(i => i.id !== item.id))} className="p-2 text-rose-500 hover:bg-rose-50 rounded-lg transition-colors"><Trash2 size={14}/></button>}
