                  <div>
                    <h3 className="text-sm font-black text-slate-900 uppercase tracking-tight">{session.institution}</h3>
                    <p className="text-[7px] font-black text-indigo-500 uppercase tracking-widest">Resumo Consolidado do Fechamento</p>
                  </div>
                </div>
                <div className="text-right">
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Referência</p>
                   <p className="text-xs font-black text-slate-900">{date.split('-').reverse().join('/')}</p>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-4">
                   <h4 className="text-[10px] font-black uppercase text-slate-900 border-b border-slate-100 pb-2">Porcentagens de Repasse</h4>
                   <div className="space-y-3">
                     <div className="flex justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                        <span className="text-[9px] font-black uppercase text-slate-400">Receita Bruta (100%)</span>
