import React, { useState, useEffect } from 'react';
import { FinancialReport, UserSession } from '../types';
import { getReports, getSettings, deleteReport, updateReportLockStatus } from '../services/storageService';
import { Calendar, Search, RefreshCw, ImageIcon, X, Send, Eye, Download, FileDown, Edit3, Trash2, Lock, Unlock, AlertTriangle, Trash } from 'lucide-react';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface ReportHistoryProps {
  session: UserSession;
  onBack: () => void;
  onEdit?: (report: FinancialReport, readOnly?: boolean) => void;
  onGoToTrash?: () => void;
}

export const ReportHistory: React.FC<ReportHistoryProps> = ({ session, onBack, onEdit, onGoToTrash }) => {
  const [reports, setReports] = useState<FinancialReport[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewingPhotos, setViewingPhotos] = useState<FinancialReport | null>(null);

  const fetchReports = async () => {
    try {
      setLoading(true);
      const allReports = await getReports();
      const filtered = allReports.filter(r => session.role === 'ADMIN' || r.institutionName.toLowerCase() === session.institution.toLowerCase());
      setReports(filtered);
    } catch (err) { console.error(err); } finally { setLoading(false); }
  };

  useEffect(() => {
    fetchReports();
    const handleUpdate = () => fetchReports();
    window.addEventListener('reports-updated', handleUpdate);
    return () => window.removeEventListener('reports-updated', handleUpdate);
  }, []);

  const handleDeleteReport = async (id: string) => {
    if (confirm("Deseja realmente enviar este relatório para a lixeira?")) {
      try {
        await deleteReport(id, session.name);
        // O notifyUpdate no service já deve disparar o fetchReports via event listener
      } catch (err) {
        alert("Erro ao excluir relatório. Verifique sua conexão.");
      }
    }
  };

  const handleToggleLock = async (report: FinancialReport) => {
    if (session.role !== 'ADMIN') return;
    const newStatus = !report.locked;
    if (confirm(`Deseja ${newStatus ? 'FECHAR' : 'ABRIR'} este período? ${newStatus ? 'Tesoureiros não poderão mais editar.' : 'Edições serão permitidas novamente.'}`)) {
      try {
        await updateReportLockStatus(report.id, newStatus);
      } catch (err) {
        alert("Erro ao alterar status de bloqueio.");
      }
    }
  };

  const formatBRL = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

  const generatePDF = async (report: FinancialReport) => {
    const settings = await getSettings();
    const doc = new jsPDF() as any;
    const pageWidth = doc.internal.pageSize.getWidth();
    let currentY = 20;

    // Logo em destaque no PDF (Se existir)
    if (settings.logo) {
      try { 
        const logoWidth = 35;
        const logoHeight = 35;
        doc.addImage(settings.logo, 'PNG', (pageWidth / 2) - (logoWidth / 2), currentY, logoWidth, logoHeight); 
        currentY += logoHeight + 10;
      } catch (e) {
        console.error("Erro ao carregar logo no PDF", e);
        currentY += 10;
      }
    }

    doc.setFontSize(14); doc.setFont("helvetica", "bold"); doc.setTextColor(30, 41, 59);
    doc.text(settings.institutionName.toUpperCase(), pageWidth / 2, currentY, { align: 'center' });

    doc.setFontSize(8); doc.setFont("helvetica", "normal"); doc.setTextColor(100, 116, 139);
    doc.text(`Relatório Gerado em: ${new Date().toLocaleDateString('pt-BR')}`, pageWidth / 2, currentY + 6, { align: 'center' });
    currentY += 20;

    doc.setFillColor(79, 70, 229);
    doc.roundedRect(15, currentY, pageWidth - 30, 12, 2, 2, 'F');
    doc.setFontSize(10); doc.setTextColor(255, 255, 255); doc.setFont("helvetica", "bold");
    doc.text(`FECHAMENTO SEMANAL: ${report.institutionName.toUpperCase()}`, 20, currentY + 8);
    doc.text(`REF: ${report.date.split('-').reverse().join('/')}`, pageWidth - 20, currentY + 8, { align: 'right' });
    currentY += 20;

    doc.autoTable({
      startY: currentY,
      head: [['Descritivo de Receitas', 'Valor']],
      body: [
        ['Dízimos', formatBRL(report.tithes)],
        ['Ofertas Gerais', formatBRL(report.offers)],
        ['Ofertas Especiais', formatBRL(report.specialOffers)],
        ['Receita Financeira', formatBRL(report.financialRevenue)],
        ...report.otherRevenues.map(r => [r.description || 'Outra Receita', formatBRL(r.value)]),
        [{ content: 'TOTAL BRUTO (100%)', styles: { fontStyle: 'bold', fillColor: [241, 245, 249] } }, { content: formatBRL(report.totalRevenue), styles: { fontStyle: 'bold', halign: 'right', fillColor: [241, 245, 249] } }]
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
      columnStyles: { 1: { halign: 'right' } }
    });

    currentY = doc.lastAutoTable.finalY + 10;

    doc.autoTable({
      startY: currentY,
      head: [['Distribuição e Despesas Unidade', 'Valor']],
      body: [
        ['Repasse Sede (20%)', formatBRL(report.sedeExpense)],
        ['Prebenda Pastoral (20%)', formatBRL(report.prebendaExpense)],
        ['Líquido para Unidade (60%)', formatBRL(report.totalRevenue * 0.6)],
        ['Aluguel', formatBRL(report.rent)],
        ['Energia Elétrica', formatBRL(report.energy)],
        ['Água / Saneamento', formatBRL(report.water)],
        ...report.otherExpenses.map(e => [e.description || 'Despesa Extra', formatBRL(e.value)]),
        [{ content: 'TOTAL SAÍDAS OPERACIONAIS', styles: { fontStyle: 'bold', fillColor: [254, 242, 242] } }, { content: formatBRL(report.totalFixedExpenses), styles: { fontStyle: 'bold', halign: 'right', fillColor: [254, 242, 242] } }]
      ],
      theme: 'grid',
      headStyles: { fillColor: [244, 63, 94] },
      columnStyles: { 1: { halign: 'right' } }
    });

    currentY = doc.lastAutoTable.finalY + 15;

    doc.setFillColor(15, 23, 42);
    doc.roundedRect(15, currentY, pageWidth - 30, 20, 3, 3, 'F');
    doc.setFontSize(12); doc.setTextColor(255, 255, 255); doc.setFont("helvetica", "bold");
    doc.text("SALDO LÍQUIDO FINAL GU:", 22, currentY + 12);
    doc.text(formatBRL(report.saldoGU), pageWidth - 22, currentY + 12, { align: 'right' });

    doc.save(`ADGU_Relatorio_${report.institutionName.replace(/\s+/g, '_')}_${report.date}.pdf`);
  };

  const shareWhatsApp = async (report: FinancialReport) => {
    generatePDF(report);
    const phone = "5585920003598";
    const message = `*RELATÓRIO FINANCEIRO ADGU*%0A%0A` +
      `🏛️ *Unidade:* ${report.institutionName}%0A` +
      `📅 *Referência:* ${report.date.split('-').reverse().join('/')}%0A%0A` +
      `💰 *ENTRADAS (100%):*%0A` +
      `- Bruto: *${formatBRL(report.totalRevenue)}*%0A%0A` +
      `📉 *REPASSES (40%):*%0A` +
      `- Sede (20%): ${formatBRL(report.sedeExpense)}%0A` +
      `- Prebenda (20%): ${formatBRL(report.prebendaExpense)}%0A%0A` +
      `🏠 *DISPONÍVEL UNIDADE (60%):*%0A` +
      `- Valor: ${formatBRL(report.totalRevenue * 0.6)}%0A` +
      `- Despesas Pagas: ${formatBRL(report.totalFixedExpenses)}%0A%0A` +
      `✅ *SALDO LÍQUIDO GU:*%0A` +
      `👉 *${formatBRL(report.saldoGU)}*%0A%0A` +
      `_Arquivo PDF detalhado gerado para anexo._`;

    window.open(`https://wa.me/${phone}?text=${message}`, '_blank');
  };

  const filtered = reports.filter(r => r.institutionName.toLowerCase().includes(searchTerm.toLowerCase()));

  // Regra de Permissão: ADMIN pode tudo. USER pode apenas se for dono e não estiver trancado.
  const canManage = (report: FinancialReport) => {
    if (session.role === 'ADMIN') return true;
    return report.userId === session.id && !report.locked;
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      <div className="flex flex-col md:flex-row gap-4">
        <div className="bg-white p-5 rounded-[2rem] border border-slate-100 shadow-soft flex-1 flex gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
            <input 
              type="text" 
              placeholder="Buscar unidade ou data..." 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)} 
              className="w-full pl-12 pr-4 py-3.5 bg-slate-50 rounded-2xl border border-transparent outline-none font-bold text-xs focus:bg-white focus:border-indigo-100 transition-all" 
            />
          </div>
        </div>

        {session.role === 'ADMIN' && (
          <button 
            onClick={onGoToTrash}
            className="p-5 bg-white text-slate-400 border border-slate-100 rounded-[2rem] shadow-soft hover:text-rose-500 transition-colors flex items-center gap-3 active-scale"
          >
            <Trash size={20} />
            <span className="text-[10px] font-black uppercase tracking-widest hidden md:inline">Lixeira</span>
          </button>
        )}
      </div>

      <div className="grid gap-4">
        {loading ? (
          <div className="py-20 flex flex-col items-center justify-center gap-4">
            <RefreshCw className="animate-spin text-indigo-500" size={32} />
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Buscando Relatórios...</p>
          </div>
        ) : filtered.length === 0 ? (
          <div className="py-20 text-center bg-white rounded-[2rem] border border-dashed border-slate-200">
            <FileDown size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nenhum relatório encontrado</p>
          </div>
        ) : (
          filtered.map(report => (
            <div key={report.id} className={`bg-white p-6 rounded-[2.5rem] border shadow-sm flex flex-col sm:flex-row items-center justify-between group transition-all gap-4 ${report.locked ? 'border-slate-100 bg-slate-50/30' : 'border-slate-50 hover:border-indigo-100'}`}>
              <div className="flex items-center gap-4 w-full sm:w-auto">
                <div className={`p-4 rounded-3xl transition-all shadow-sm ${report.locked ? 'bg-slate-200 text-slate-500' : 'bg-indigo-50 text-indigo-500 group-hover:bg-indigo-600 group-hover:text-white'}`}>
                  {report.locked ? <Lock size={28} /> : <Calendar size={28} />}
                </div>
                <div>
                  <div className="flex items-center gap-2">
                    <h4 className="text-xs font-black uppercase text-slate-900 tracking-tight">{report.date.split('-').reverse().join('/')}</h4>
                    {report.locked && <span className="bg-amber-100 text-amber-700 px-2 py-0.5 rounded-full text-[6px] font-black uppercase">Período Fechado</span>}
                  </div>
                  <p className="text-[8px] font-black text-indigo-500 uppercase tracking-widest">{report.institutionName}</p>
                  <p className="text-[10px] font-black text-emerald-600 mt-1">{formatBRL(report.saldoGU)}</p>
                </div>
              </div>

              <div className="flex flex-wrap justify-center sm:justify-end gap-2 w-full sm:w-auto">
                {session.role === 'ADMIN' && (
                  <button onClick={() => handleToggleLock(report)} className={`p-3 rounded-2xl active-scale transition-colors ${report.locked ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`} title={report.locked ? 'Abrir Período' : 'Fechar Período'}>
                    {report.locked ? <Unlock size={18}/> : <Lock size={18}/>}
                  </button>
                )}

                {report.attachments?.length > 0 && (
                  <button onClick={() => setViewingPhotos(report)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-slate-100 transition-colors active-scale" title="Ver Anexos">
                    <ImageIcon size={18}/>
                  </button>
                )}

                <button onClick={() => onEdit?.(report, true)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-slate-100 transition-colors active-scale" title="Visualizar">
                  <Eye size={18}/>
                </button>

                {canManage(report) && (
                  <>
                    <button onClick={() => onEdit?.(report, false)} className="p-3 bg-indigo-50 text-indigo-600 rounded-2xl hover:bg-indigo-600 hover:text-white transition-all active-scale" title="Editar">
                      <Edit3 size={18}/>
                    </button>
                    <button onClick={() => handleDeleteReport(report.id)} className="p-3 bg-rose-50 text-rose-500 rounded-2xl hover:bg-rose-500 hover:text-white transition-all active-scale" title="Excluir">
                      <Trash2 size={18}/>
                    </button>
                  </>
                )}

                <button onClick={() => shareWhatsApp(report)} className="p-3 px-5 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center gap-2 hover:bg-emerald-600 hover:text-white transition-all active-scale shadow-sm">
                  <Send size={18} />
                  <span className="text-[8px] font-black uppercase tracking-widest">Enviar</span>
                </button>
              </div>
            </div>
          ))
        )}
      </div>

      {viewingPhotos && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 animate-in fade-in duration-300">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-md" onClick={() => setViewingPhotos(null)} />
          <div className="relative w-full max-w-4xl bg-white rounded-[2.5rem] p-8 shadow-3xl flex flex-col max-h-[90vh]">
             <div className="flex justify-between items-center mb-6 px-4">
                <div>
                  <h3 className="text-lg font-black text-slate-900 uppercase tracking-tight">Anexos</h3>
                  <p className="text-[8px] font-black text-indigo-500 uppercase tracking-widest">{viewingPhotos.institutionName}</p>
                </div>
                <button onClick={() => setViewingPhotos(null)} className="p-2 bg-slate-100 rounded-xl text-slate-400"><X size={24}/></button>
             </div>
             <div className="flex-1 overflow-y-auto grid grid-cols-1 sm:grid-cols-2 gap-4 p-4 no-scrollbar">
                {viewingPhotos.attachments.map((file, idx) => (
                  <div key={idx} className="relative rounded-3xl overflow-hidden border bg-slate-50 shadow-sm group">
                    <img src={file.data} className="w-full h-64 object-cover" />
                    <button onClick={() => { const l=document.createElement('a'); l.href=file.data; l.download=`anexo_${idx}.jpg`; l.click(); }} className="absolute bottom-4 right-4 p-3 bg-white text-slate-900 rounded-xl shadow-lg opacity-0 group-hover:opacity-100 transition-opacity">
                      <Download size={16}/>
                    </button>
                  </div>
                ))}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

import { FinancialReport, UserAccount, DailyTransaction } from '../types';
import { supabase } from './supabaseClient';

export interface SystemSettings {
  logo?: string;
  institutionName: string;
  cnpj: string;
  address: string;
  email: string;
  president: string;
  closingDay: number;
}

const notifyUpdate = (event: string) => {
  window.dispatchEvent(new Event(event));
};

const safeNum = (val: any): number => {
  const n = Number(val);
  return isNaN(n) ? 0 : n;
};

export const getUserByUsername = async (username: string): Promise<UserAccount | null> => {
  const userClean = username.toLowerCase().trim();
  try {
    const { data, error } = await supabase
      .from('users')
      .select('*')
      .eq('username', userClean)
      .eq('active', true) 
      .maybeSingle();

    if (error || !data) return null;

    return {
      id: data.id,
      username: data.username,
      password: data.password,
      name: data.name,
      phone: data.phone,
      photo: data.photo,
      role: data.role as any,
      institution: data.institution || '', 
      active: data.active ?? true
    };
  } catch {
    return null;
  }
};

