import React, { useState, useEffect } from 'react';
import { FinancialReport, UserSession } from '../types';
import { getReports, getSettings, deleteReport, updateReportLockStatus } from '../services/storageService';
import { Calendar, Search, RefreshCw, ImageIcon, X, Send, Eye, Download, FileDown, Edit3, Trash2, Lock, Unlock, AlertTriangle, Trash } from 'lucide-react';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface ReportHistoryProps {
  session: UserSession;
  onBack: () => void;
  onEdit?: (report: FinancialReport, readOnly?: boolean) => void;
  onGoToTrash?: () => void;
}

export const ReportHistory: React.FC<ReportHistoryProps> = ({ session, onBack, onEdit, onGoToTrash }) => {
  const [reports, setReports] = useState<FinancialReport[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewingPhotos, setViewingPhotos] = useState<FinancialReport | null>(null);

  const fetchReports = async () => {
    try {
      setLoading(true);
      const allReports = await getReports();
      // Filtragem por unidade para usuários comuns
      const filtered = allReports.filter(r => 
        session.role === 'ADMIN' || 
        r.institutionName.toLowerCase() === session.institution.toLowerCase()
      );
      setReports(filtered);
    } catch (err) { 
      console.error(err); 
    } finally { 
      setLoading(false); 
    }
  };

  useEffect(() => {
    fetchReports();
    const handleUpdate = () => fetchReports();
    window.addEventListener('reports-updated', handleUpdate);
    return () => window.removeEventListener('reports-updated', handleUpdate);
  }, [session.institution]);

  const handleDeleteReport = async (id: string) => {
    if (confirm("Deseja realmente mover este relatório para a lixeira?")) {
      try {
        await deleteReport(id, session.name);
      } catch (err) {
        alert("Erro ao excluir. Verifique sua permissão.");
      }
    }
  };

  const handleToggleLock = async (report: FinancialReport) => {
    if (session.role !== 'ADMIN') return;
    const newStatus = !report.locked;
    if (confirm(`Deseja ${newStatus ? 'FECHAR' : 'ABRIR'} este período?`)) {
      try {
        await updateReportLockStatus(report.id, newStatus);
      } catch (err) {
        alert("Erro ao alterar bloqueio.");
      }
    }
  };

  const formatBRL = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

  const generatePDF = async (report: FinancialReport) => {
    const settings = await getSettings();
    const doc = new jsPDF() as any;
    const pageWidth = doc.internal.pageSize.getWidth();
    let currentY = 20;

    if (settings.logo) {
      try { 
        const logoWidth = 35;
        const logoHeight = 35;
        doc.addImage(settings.logo, 'PNG', (pageWidth / 2) - (logoWidth / 2), currentY, logoWidth, logoHeight); 
        currentY += logoHeight + 10;
      } catch (e) {
        currentY += 10;
      }
    }

    doc.setFontSize(14); doc.setFont("helvetica", "bold"); doc.setTextColor(30, 41, 59);
    doc.text(settings.institutionName.toUpperCase(), pageWidth / 2, currentY, { align: 'center' });
    currentY += 20;

    doc.autoTable({
      startY: currentY,
      head: [['Descritivo Financeiro', 'Valor']],
      body: [
        ['Dízimos', formatBRL(report.tithes)],
        ['Ofertas Gerais', formatBRL(report.offers)],
        ['Ofertas Especiais', formatBRL(report.specialOffers)],
        ['Receita Financeira', formatBRL(report.financialRevenue)],
        ...report.otherRevenues.map(r => [r.description || 'Outra Receita', formatBRL(r.value)]),
        [{ content: 'TOTAL BRUTO (100%)', styles: { fontStyle: 'bold' } }, { content: formatBRL(report.totalRevenue), styles: { fontStyle: 'bold', halign: 'right' } }]
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
      columnStyles: { 1: { halign: 'right' } }
    });

    currentY = doc.lastAutoTable.finalY + 15;
    doc.setFontSize(12); doc.setTextColor(15, 23, 42);
    doc.text(`SALDO LÍQUIDO FINAL GU: ${formatBRL(report.saldoGU)}`, 15, currentY);

    doc.save(`ADGU_Relatorio_${report.institutionName}_${report.date}.pdf`);
  };

  const filtered = reports.filter(r => r.institutionName.toLowerCase().includes(searchTerm.toLowerCase()));

  // Regra de Permissão: ADMIN pode tudo. USER pode apenas se for dono e NÃO estiver trancado.
  const canManage = (report: FinancialReport) => {
    if (session.role === 'ADMIN') return true;
    return report.userId === session.id && !report.locked;
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      <div className="flex flex-col md:flex-row gap-4">
        <div className="bg-white p-5 rounded-[2rem] border border-slate-100 shadow-soft flex-1 flex gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
            <input 
              type="text" 
              placeholder="Buscar unidade ou data..." 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)} 
              className="w-full pl-12 pr-4 py-3.5 bg-slate-50 rounded-2xl border border-transparent outline-none font-bold text-xs focus:bg-white transition-all" 
            />
          </div>
        </div>

        {session.role === 'ADMIN' && (
          <button 
            onClick={onGoToTrash}
            className="p-5 bg-white text-slate-400 border border-slate-100 rounded-[2rem] shadow-soft hover:text-rose-500 transition-colors flex items-center gap-3 active-scale"
          >
            <Trash size={20} />
            <span className="text-[10px] font-black uppercase tracking-widest hidden md:inline">Lixeira</span>
          </button>
        )}
      </div>

      <div className="grid gap-4">
        {loading ? (
          <div className="py-20 flex flex-col items-center justify-center gap-4">
            <RefreshCw className="animate-spin text-indigo-500" size={32} />
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizando Banco de Dados...</p>
          </div>
        ) : filtered.length === 0 ? (
          <div className="py-20 text-center bg-white rounded-[2rem] border border-dashed border-slate-200">
            <FileDown size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nenhum relatório encontrado</p>
          </div>
        ) : (
          filtered.map(report => (
            <div key={report.id} className={`bg-white p-6 rounded-[2.5rem] border shadow-sm flex flex-col sm:flex-row items-center justify-between group transition-all gap-4 ${report.locked ? 'bg-slate-50/50 border-slate-100' : 'border-slate-50 hover:border-indigo-100'}`}>
              <div className="flex items-center gap-4 w-full sm:w-auto">
                <div className={`p-4 rounded-3xl transition-all shadow-sm ${report.locked ? 'bg-slate-200 text-slate-500' : 'bg-indigo-50 text-indigo-500'}`}>
                  {report.locked ? <Lock size={28} /> : <Calendar size={28} />}
                </div>
                <div>
                  <div className="flex items-center gap-2">
                    <h4 className="text-xs font-black uppercase text-slate-900 tracking-tight">{report.date.split('-').reverse().join('/')}</h4>
                    {report.locked && <span className="bg-amber-100 text-amber-700 px-2 py-0.5 rounded-full text-[6px] font-black uppercase">Período Fechado</span>}
                  </div>
                  <p className="text-[8px] font-black text-indigo-500 uppercase tracking-widest">{report.institutionName}</p>
                  <p className="text-[10px] font-black text-emerald-600 mt-1">{formatBRL(report.saldoGU)}</p>
                </div>
              </div>

              <div className="flex flex-wrap justify-center sm:justify-end gap-2 w-full sm:w-auto">
                {session.role === 'ADMIN' && (
                  <button onClick={() => handleToggleLock(report)} className={`p-3 rounded-2xl active-scale transition-colors ${report.locked ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                    {report.locked ? <Unlock size={18}/> : <Lock size={18}/>}
                  </button>
                )}

                <button onClick={() => onEdit?.(report, true)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-slate-100 transition-colors active-scale">
                  <Eye size={18}/>
                </button>

                {canManage(report) && (
                  <>
                    <button onClick={() => onEdit?.(report, false)} className="p-3 bg-indigo-50 text-indigo-600 rounded-2xl hover:bg-indigo-600 hover:text-white transition-all active-scale">
                      <Edit3 size={18}/>
                    </button>
                    <button onClick={() => handleDeleteReport(report.id)} className="p-3 bg-rose-50 text-rose-500 rounded-2xl hover:bg-rose-500 hover:text-white transition-all active-scale">
                      <Trash2 size={18}/>
                    </button>
                  </>
                )}

                <button onClick={() => generatePDF(report)} className="p-3 px-5 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center gap-2 hover:bg-emerald-600 hover:text-white transition-all active-scale shadow-sm">
                  <Download size={18} />
                  <span className="text-[8px] font-black uppercase tracking-widest">PDF</span>
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { UserAccount, UserSession } from '../types';
import { getUsers, updateUserStatus, saveUser } from '../services/storageService';
import { UserCheck, UserX, ShieldCheck, Mail, Phone, MapPin, PlusCircle, X, Loader2, CheckCircle, Shield, Key, UserCircle, Edit3 } from 'lucide-react';

export const UserManagement: React.FC<{ session: UserSession }> = ({ session }) => {
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  const [formData, setFormData] = useState<Partial<UserAccount>>({
    name: '',
    username: '',
    password: '',
    institution: '',
    phone: '',
    role: 'USER',
    active: true
  });

  const [isEditing, setIsEditing] = useState(false);

  useEffect(() => {
    loadUsers();
    const handleUpdate = () => loadUsers();
    window.addEventListener('users-updated', handleUpdate);
    return () => window.removeEventListener('users-updated', handleUpdate);
  }, []);

  const loadUsers = async () => {
    setLoading(true);
    try {
      const data = await getUsers();
      setUsers(data);
    } catch (err) {
      console.error("Erro ao carregar usuários:", err);
    } finally {
      setLoading(false);
    }
  };

  const toggleStatus = async (id: string, current: boolean) => {
    try {
      await updateUserStatus(id, !current);
      setSuccessMessage(current ? "Usuário bloqueado" : "Usuário ativado");
      setTimeout(() => setSuccessMessage(null), 3000);
    } catch (err) {
      alert("Erro ao alterar status.");
    }
  };

  const handleOpenCreate = () => {
    setIsEditing(false);
    setFormData({
      name: '',
      username: '',
      password: '',
      institution: '',
      phone: '',
      role: 'USER',
      active: true
    });
    setShowModal(true);
  };

  const handleOpenEdit = (user: UserAccount) => {
    setIsEditing(true);
    setFormData({ ...user });
    setShowModal(true);
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.username || !formData.password || !formData.institution) {
      alert("Por favor, preencha todos os campos obrigatórios.");
      return;
    }

    setIsSaving(true);
    try {
      await saveUser(formData);
      setSuccessMessage(isEditing ? "Dados atualizados com sucesso!" : "Tesoureiro cadastrado com sucesso!");
      setTimeout(() => setSuccessMessage(null), 3000);
      setShowModal(false);
    } catch (err) {
      alert("Erro ao salvar usuário. O login pode já estar em uso.");
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-10">
      {successMessage && (
        <div className="fixed top-10 left-1/2 -translate-x-1/2 z-[300] bg-emerald-500 text-white px-8 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-500">
          <CheckCircle size={20} />
          <span className="text-[10px] font-black uppercase tracking-widest">{successMessage}</span>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Gestão da Equipe</h2>
          <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mt-0.5">Controle total de acessos e unidades</p>
        </div>
        <button 
          onClick={handleOpenCreate}
          className="flex items-center justify-center gap-2 px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest active-scale shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all"
        >
          <PlusCircle size={18}/> Adicionar Novo Membro
        </button>
      </div>

      {loading ? (
        <div className="p-20 flex flex-col items-center justify-center space-y-4">
           <Loader2 className="animate-spin text-indigo-500" size={32} />
           <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest">Sincronizando usuários...</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {users.map(u => (
            <div key={u.id} className={`bg-white p-8 rounded-[2.5rem] border shadow-sm relative overflow-hidden flex flex-col items-center text-center group transition-all ${u.active ? 'border-slate-50 hover:border-indigo-100' : 'border-rose-100 bg-rose-50/20'}`}>

              <div className="absolute top-4 right-4 flex gap-2">
                <button 
                  onClick={() => handleOpenEdit(u)}
                  className="p-2.5 bg-slate-50 text-slate-400 rounded-xl hover:bg-indigo-50 hover:text-indigo-600 transition-all active-scale"
                  title="Editar dados"
                >
                  <Edit3 size={16} />
                </button>
                <div className={`p-2.5 rounded-xl ${u.active ? 'bg-emerald-50 text-emerald-500' : 'bg-rose-50 text-rose-500'}`}>
                  {u.role === 'ADMIN' ? <Shield size={16} /> : <UserCircle size={16} />}
                </div>
              </div>

              <div className="w-24 h-24 bg-slate-900 rounded-[2rem] mb-6 flex items-center justify-center text-white font-black text-2xl uppercase border-4 border-white shadow-xl overflow-hidden group-hover:scale-105 transition-transform">
                {u.photo ? <img src={u.photo} className="w-full h-full object-cover" /> : u.name.charAt(0)}
              </div>

              <h3 className="text-sm font-black text-slate-900 uppercase tracking-tight">{u.name}</h3>
              <p className="text-[8px] font-black text-indigo-500 uppercase tracking-widest mt-1 mb-6">{u.institution}</p>

              <div className="w-full space-y-2 mb-8 bg-slate-50/50 p-4 rounded-2xl border border-slate-100">
                <div className="flex items-center justify-center gap-2 text-[8px] font-black text-slate-400 uppercase">
                  <UserCircle size={12} className="text-indigo-300"/> @{u.username}
                </div>
                <div className="flex items-center justify-center gap-2 text-[8px] font-black text-slate-400 uppercase">
                  <Phone size={12} className="text-indigo-300"/> {u.phone || 'Sem Telefone'}
                </div>
              </div>

              {u.id !== session.id && (
                <button 
                  onClick={() => toggleStatus(u.id, u.active)}
                  className={`w-full py-4 rounded-2xl font-black text-[9px] uppercase tracking-widest active-scale flex items-center justify-center gap-2 border transition-all ${
                    u.active 
                      ? 'bg-white text-rose-500 border-rose-100 hover:bg-rose-500 hover:text-white' 
                      : 'bg-emerald-600 text-white border-transparent hover:bg-emerald-700'
                  }`}
                >
                  {u.active ? <UserX size={16}/> : <UserCheck size={16}/>}
                  {u.active ? 'Bloquear Acesso' : 'Ativar Usuário'}
                </button>
              )}

              {u.id === session.id && (
                <div className="w-full py-4 rounded-2xl font-black text-[9px] uppercase tracking-widest bg-slate-100 text-slate-400 border border-slate-200">
                  Sua Conta (Logado)
                </div>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Modal de Cadastro/Edição de Usuário */}
      {showModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/70 backdrop-blur-md animate-in fade-in duration-300" onClick={() => !isSaving && setShowModal(false)} />
          <div className="relative w-full max-w-lg bg-white rounded-[3rem] p-10 shadow-3xl animate-in zoom-in-95 duration-500">
             <div className="flex justify-between items-center mb-8">
                <div>
                  <h3 className="text-xl font-black uppercase text-slate-900 tracking-tight">
                    {isEditing ? 'Atualizar Membro' : 'Novo Tesoureiro'}
                  </h3>
                  <p className="text-[8px] font-black text-indigo-500 uppercase tracking-widest mt-1">
                    {isEditing ? 'Modificando credenciais existentes' : 'Cadastro de Acesso Ministerial'}
                  </p>
                </div>
                <button onClick={() => setShowModal(false)} className="p-2 bg-slate-50 text-slate-300 hover:text-slate-900 rounded-xl transition-colors"><X size={20}/></button>
             </div>

             <form onSubmit={handleSaveUser} className="space-y-6">
                <div className="space-y-4">
                   <div className="space-y-1">
                      <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Nome Completo</label>
                      <input 
                        type="text" 
                        required 
                        value={formData.name} 
                        onChange={e => setFormData({...formData, name: e.target.value})} 
                        className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold text-xs border border-transparent focus:bg-white focus:border-indigo-100 transition-all" 
                        placeholder="Ex: João da Silva" 
                      />
                   </div>

                   <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-1">
                        <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Usuário (Login)</label>
                        <input 
                          type="text" 
                          required 
                          disabled={isEditing}
                          value={formData.username} 
                          onChange={e => setFormData({...formData, username: e.target.value.toLowerCase().trim()})} 
                          className={`w-full p-4 rounded-2xl font-black text-xs border border-transparent focus:bg-white focus:border-indigo-100 outline-none ${isEditing ? 'bg-slate-100 text-slate-400 cursor-not-allowed' : 'bg-slate-50'}`} 
                          placeholder="joao.silva" 
                        />
