import React, { useState, useEffect } from 'react';
import { FinancialReport, UserSession } from '../types';
import { getReports, getSettings, deleteReport, updateReportLockStatus } from '../services/storageService';
import { Calendar, Search, RefreshCw, ImageIcon, X, Send, Eye, Download, FileDown, Edit3, Trash2, Lock, Unlock, AlertTriangle, Trash } from 'lucide-react';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface ReportHistoryProps {
  session: UserSession;
  onBack: () => void;
  onEdit?: (report: FinancialReport, readOnly?: boolean) => void;
  onGoToTrash?: () => void;
}

export const ReportHistory: React.FC<ReportHistoryProps> = ({ session, onBack, onEdit, onGoToTrash }) => {
  const [reports, setReports] = useState<FinancialReport[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewingPhotos, setViewingPhotos] = useState<FinancialReport | null>(null);

  const fetchReports = async () => {
    try {
      setLoading(true);
      const allReports = await getReports();
      // Filtragem por unidade para usuários comuns (Tesoureiros)
      // Admins veem tudo.
      const filtered = allReports.filter(r => 
        session.role === 'ADMIN' || 
        r.institutionName.toLowerCase() === session.institution.toLowerCase()
      );
      setReports(filtered);
    } catch (err) { 
      console.error("Erro ao buscar relatórios:", err); 
    } finally { 
      setLoading(false); 
    }
  };

  useEffect(() => {
    fetchReports();
    const handleUpdate = () => fetchReports();
    window.addEventListener('reports-updated', handleUpdate);
    return () => window.removeEventListener('reports-updated', handleUpdate);
  }, [session.institution]);

  const handleDeleteReport = async (id: string) => {
    if (confirm("Deseja realmente mover este relatório para a lixeira?")) {
      try {
        await deleteReport(id, session.name);
        // O evento 'reports-updated' disparado pelo service atualizará a lista
      } catch (err) {
        alert("Erro ao excluir. Verifique sua conexão ou permissões.");
      }
    }
  };

  const handleToggleLock = async (report: FinancialReport) => {
    if (session.role !== 'ADMIN') return;
    const newStatus = !report.locked;
    if (confirm(`Deseja ${newStatus ? 'FECHAR' : 'ABRIR'} este período para edições?`)) {
      try {
        await updateReportLockStatus(report.id, newStatus);
      } catch (err) {
        alert("Erro ao alterar bloqueio.");
      }
    }
  };

  const formatBRL = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

  const generatePDF = async (report: FinancialReport) => {
    const settings = await getSettings();
    const doc = new jsPDF() as any;
    const pageWidth = doc.internal.pageSize.getWidth();
    let currentY = 20;

    if (settings.logo) {
      try { 
        const logoWidth = 35;
        const logoHeight = 35;
        doc.addImage(settings.logo, 'PNG', (pageWidth / 2) - (logoWidth / 2), currentY, logoWidth, logoHeight); 
        currentY += logoHeight + 10;
      } catch (e) {
        currentY += 10;
      }
    }

    doc.setFontSize(14); doc.setFont("helvetica", "bold"); doc.setTextColor(30, 41, 59);
    doc.text(settings.institutionName.toUpperCase(), pageWidth / 2, currentY, { align: 'center' });
    currentY += 20;

    doc.autoTable({
      startY: currentY,
      head: [['Descritivo Financeiro', 'Valor']],
      body: [
        ['Dízimos', formatBRL(report.tithes)],
        ['Ofertas Gerais', formatBRL(report.offers)],
        ['Ofertas Especiais', formatBRL(report.specialOffers)],
        ['Receita Financeira', formatBRL(report.financialRevenue)],
        ...report.otherRevenues.map(r => [r.description || 'Outra Receita', formatBRL(r.value)]),
        [{ content: 'TOTAL BRUTO (100%)', styles: { fontStyle: 'bold', fillColor: [241, 245, 249] } }, { content: formatBRL(report.totalRevenue), styles: { fontStyle: 'bold', halign: 'right', fillColor: [241, 245, 249] } }]
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
      columnStyles: { 1: { halign: 'right' } }
    });

    currentY = doc.lastAutoTable.finalY + 15;
    doc.setFontSize(12); doc.setTextColor(15, 23, 42);
    doc.text(`SALDO LÍQUIDO FINAL GU: ${formatBRL(report.saldoGU)}`, 15, currentY);

    doc.save(`ADGU_Relatorio_${report.institutionName.replace(/\s+/g, '_')}_${report.date}.pdf`);
  };

  const filtered = reports.filter(r => r.institutionName.toLowerCase().includes(searchTerm.toLowerCase()));

  // REGRA DE OURO DAS PERMISSÕES:
  const canManage = (report: FinancialReport) => {
    // 1. Administrador sempre pode gerenciar tudo.
    if (session.role === 'ADMIN') return true;

    // 2. Tesoureiro comum só pode se pertencer à unidade E o período não estiver trancado.
    const isSameUnit = report.institutionName.toLowerCase() === session.institution.toLowerCase();
    const isNotLocked = !report.locked;

    return isSameUnit && isNotLocked;
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      <div className="flex flex-col md:flex-row gap-4">
        <div className="bg-white p-5 rounded-[2rem] border border-slate-100 shadow-soft flex-1 flex gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
            <input 
              type="text" 
              placeholder="Buscar unidade ou data..." 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)} 
              className="w-full pl-12 pr-4 py-3.5 bg-slate-50 rounded-2xl border border-transparent outline-none font-bold text-xs focus:bg-white focus:border-indigo-100 transition-all" 
            />
          </div>
        </div>

        {session.role === 'ADMIN' && (
          <button 
            onClick={onGoToTrash}
            className="p-5 bg-white text-slate-400 border border-slate-100 rounded-[2rem] shadow-soft hover:text-rose-500 transition-colors flex items-center gap-3 active-scale"
          >
            <Trash size={20} />
            <span className="text-[10px] font-black uppercase tracking-widest hidden md:inline">Lixeira</span>
          </button>
        )}
      </div>

      <div className="grid gap-4">
        {loading ? (
          <div className="py-20 flex flex-col items-center justify-center gap-4">
            <RefreshCw className="animate-spin text-indigo-500" size={32} />
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizando Banco de Dados...</p>
          </div>
        ) : filtered.length === 0 ? (
          <div className="py-20 text-center bg-white rounded-[2rem] border border-dashed border-slate-200">
            <FileDown size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nenhum relatório encontrado</p>
          </div>
        ) : (
          filtered.map(report => (
            <div key={report.id} className={`bg-white p-6 rounded-[2.5rem] border shadow-sm flex flex-col sm:flex-row items-center justify-between group transition-all gap-4 ${report.locked ? 'bg-slate-50/50 border-slate-100' : 'border-slate-50 hover:border-indigo-100'}`}>
              <div className="flex items-center gap-4 w-full sm:w-auto">
                <div className={`p-4 rounded-3xl transition-all shadow-sm ${report.locked ? 'bg-slate-200 text-slate-500' : 'bg-indigo-50 text-indigo-500'}`}>
                  {report.locked ? <Lock size={28} /> : <Calendar size={28} />}
                </div>
                <div>
                  <div className="flex items-center gap-2">
                    <h4 className="text-xs font-black uppercase text-slate-900 tracking-tight">{report.date.split('-').reverse().join('/')}</h4>
                    {report.locked && <span className="bg-amber-100 text-amber-700 px-2 py-0.5 rounded-full text-[6px] font-black uppercase tracking-tighter">Período Fechado</span>}
                  </div>
                  <p className="text-[8px] font-black text-indigo-500 uppercase tracking-widest">{report.institutionName}</p>
                  <p className="text-[10px] font-black text-emerald-600 mt-1">{formatBRL(report.saldoGU)}</p>
                </div>
              </div>

              <div className="flex flex-wrap justify-center sm:justify-end gap-2 w-full sm:w-auto">
                {session.role === 'ADMIN' && (
                  <button onClick={() => handleToggleLock(report)} className={`p-3 rounded-2xl active-scale transition-colors ${report.locked ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`} title={report.locked ? "Abrir Edição" : "Trancar Período"}>
                    {report.locked ? <Unlock size={18}/> : <Lock size={18}/>}
                  </button>
                )}

                <button onClick={() => onEdit?.(report, true)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-slate-100 transition-colors active-scale" title="Visualizar">
                  <Eye size={18}/>
                </button>

                {canManage(report) && (
                  <>
                    <button onClick={() => onEdit?.(report, false)} className="p-3 bg-indigo-50 text-indigo-600 rounded-2xl hover:bg-indigo-600 hover:text-white transition-all active-scale" title="Editar">
                      <Edit3 size={18}/>
                    </button>
                    <button onClick={() => handleDeleteReport(report.id)} className="p-3 bg-rose-50 text-rose-500 rounded-2xl hover:bg-rose-500 hover:text-white transition-all active-scale" title="Excluir">
                      <Trash2 size={18}/>
                    </button>
                  </>
                )}

                <button onClick={() => generatePDF(report)} className="p-3 px-5 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center gap-2 hover:bg-emerald-600 hover:text-white transition-all active-scale shadow-sm">
                  <Download size={18} />
                  <span className="text-[8px] font-black uppercase tracking-widest">PDF</span>
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

