  const [interestRevenue, setInterestRevenue] = useState(initialData?.interestRevenue || 0);
  const [rentRevenue, setRentRevenue] = useState(initialData?.rentRevenue || 0);
  const [otherRevenues, setOtherRevenues] = useState<MiscItem[]>(initialData?.otherRevenues || []);

  // Despesas
  const [rent, setRent] = useState(initialData?.rent || 0);
  const [water, setWater] = useState(initialData?.water || 0);
  const [energy, setEnergy] = useState(initialData?.energy || 0);
  const [internet, setInternet] = useState(initialData?.internet || 0);
  const [cleaning, setCleaning] = useState(initialData?.cleaning || 0);
  const [maintenance, setMaintenance] = useState(initialData?.maintenance || 0);
  const [missions, setMissions] = useState(initialData?.missions || 0);
  const [social, setSocial] = useState(initialData?.social || 0);
  const [otherExpenses, setOtherExpenses] = useState<MiscItem[]>(initialData?.otherExpenses || []);

  // Outros
  const [attachments, setAttachments] = useState<{ name: string; type: string; data: string }[]>(initialData?.attachments || []);
  const [isSaving, setIsSaving] = useState(false);
  const [saveError, setSaveError] = useState<string | null>(null);
  const [isCompressing, setIsCompressing] = useState(false);
  const [previousBalance, setPreviousBalance] = useState(initialData?.previousBalance || 0);
  const [instLogo, setInstLogo] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    getSettings().then(s => setInstLogo(s.logo || null));
  }, []);

  const isCamposBelos = (initialData?.institutionName || session.institution).toLowerCase().replace(/\s+/g, '').includes('camposbelos');

  const compressImage = (base64Str: string): Promise<string> => {
    return new Promise((resolve) => {
      const img = new Image();
      img.src = base64Str;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX_WIDTH = 1200;
        let width = img.width;
        let height = img.height;
        if (width > MAX_WIDTH) { height *= MAX_WIDTH / width; width = MAX_WIDTH; }
        canvas.width = width; canvas.height = height;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL('image/jpeg', 0.6));
      };
    });
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (readOnly) return;
    const files = e.target.files;
    if (!files) return;
    setIsCompressing(true);
    for (const file of Array.from(files) as File[]) {
      try {
        const base64: string = await new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
        });
        const compressed = await compressImage(base64);
        setAttachments(prev => [...prev, { name: file.name, type: 'image/jpeg', data: compressed }]);
      } catch (err) { console.error(err); }
    }
    setIsCompressing(false);
  };

  const sumOtherRevenues = otherRevenues.reduce((acc, curr) => acc + (curr.value || 0), 0);
  const financialRevenueTotal = interestRevenue + rentRevenue;
  const totalRevenue = (Number(tithes) || 0) + (Number(offers) || 0) + (Number(specialOffers) || 0) + financialRevenueTotal + sumOtherRevenues;

  const sedeExpense = isCamposBelos ? 0 : totalRevenue * 0.20;
  const prebendaExpense = isCamposBelos ? 0 : totalRevenue * 0.20;
  const revenue60 = isCamposBelos ? totalRevenue : totalRevenue * 0.60;

  const sumOtherExpenses = otherExpenses.reduce((acc, curr) => acc + (curr.value || 0), 0);
  const totalFixedExpenses = (Number(rent) || 0) + (Number(water) || 0) + (Number(energy) || 0) + 
                            (Number(internet) || 0) + (Number(cleaning) || 0) + (Number(maintenance) || 0) + 
                            (Number(missions) || 0) + (Number(social) || 0) + sumOtherExpenses;

  const totalExpenses = sedeExpense + prebendaExpense + totalFixedExpenses;
  const saldoGU = revenue60 - totalFixedExpenses;
  const currentBalance = previousBalance + saldoGU;

  const formatBRL = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

  const handleSubmit = async () => {
    if (readOnly && session.role !== 'ADMIN') { onFinished(); return; }
    setIsSaving(true);
    setSaveError(null);
    const report: FinancialReport = {
      id: initialData?.id || crypto.randomUUID(),
      date, 
      institutionName: initialData?.institutionName || session.institution,
      reporterName: initialData?.reporterName || session.name, 
      userId: initialData?.userId || session.id,
      locked: initialData?.locked || false, 

      tithes, offers, specialOffers, 
      interestRevenue, rentRevenue, 
      financialRevenue: financialRevenueTotal, 
      otherRevenues,

      rent, water, energy, internet, cleaning, maintenance, missions, social,
      otherExpenses, 

      totalRevenue, 
      totalFixedExpenses, 
      sedeExpense, 
      prebendaExpense, 
      totalExpenses, 
      saldoGU, 
      currentBalance, 
      previousBalance, 
      attachments, 
      createdAt: initialData?.createdAt || new Date().toISOString()
    };
    try {
      await saveReport(report);
      onFinished();
    } catch (err: any) { 
      console.error(err);
      setSaveError(`Falha ao salvar: ${err.message || 'Erro de conexão'}`);
    } finally { setIsSaving(false); }
  };

  return (
    <div className="space-y-8 max-w-5xl mx-auto animate-in fade-in duration-700 pb-10">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 px-4">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-3 bg-white text-slate-400 rounded-xl shadow-sm hover:text-indigo-600 transition-colors active-scale"><ArrowLeft size={20}/></button>
          <div>
            <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">{readOnly ? 'Visualização Detalhada' : initialData ? 'Ajustar Fechamento' : 'Novo Fechamento'}</h2>
            <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">{session.institution}</p>
          </div>
        </div>
        {initialData?.locked && (
           <div className="bg-amber-50 text-amber-600 px-4 py-2 rounded-2xl border border-amber-100 flex items-center gap-2">
              <Calculator size={14}/>
              <span className="text-[8px] font-black uppercase tracking-widest">Período Fechado - Apenas Leitura</span>
           </div>
        )}
      </div>

      {/* Tabs */}
      <div className="flex bg-white p-2 rounded-[1.5rem] shadow-soft border border-slate-50 overflow-x-auto no-scrollbar">
        {(['RECEITAS', 'DESPESAS', 'ANEXOS', 'RESUMO'] as FormTab[]).map(tab => (
          <button key={tab} onClick={() => setActiveTab(tab)} className={`flex-1 min-w-[100px] py-4 px-6 rounded-2xl text-[9px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>{tab}</button>
        ))}
      </div>

      {/* Content */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 p-6 md:p-10 shadow-sm min-h-[400px]">
        {saveError && (
          <div className="mb-6 p-4 bg-rose-50 border border-rose-100 rounded-2xl flex items-center gap-3 text-rose-600 animate-in shake duration-300">
            <AlertCircle size={20} />
            <p className="text-[10px] font-black uppercase">{saveError}</p>
          </div>
        )}

        {activeTab === 'RECEITAS' && (
          <div className="space-y-10 animate-in slide-in-from-right-4">
             {/* Info Básica */}
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Data Referência</label>
                  <input type="date" disabled={readOnly} value={date} onChange={e => setDate(e.target.value)} className="w-full p-4 bg-slate-50 rounded-2xl border border-transparent font-bold text-xs focus:bg-white focus:border-indigo-100 transition-all outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Saldo Anterior Acumulado</label>
                  <input type="number" disabled={readOnly} value={previousBalance} onChange={e => setPreviousBalance(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl border border-transparent font-black text-xs focus:bg-white focus:border-indigo-100 transition-all outline-none" />
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                {/* Entradas Ministeriais */}
                <div className="space-y-6">
                   <div className="flex items-center gap-2 border-b border-indigo-50 pb-2">
                     <TrendingUp className="text-indigo-500" size={16}/>
                     <h4 className="text-[10px] font-black uppercase text-indigo-500">Entradas Ministeriais (100%)</h4>
                   </div>
                   <div className="space-y-4">
                      {[
                        { label: 'Dízimos', val: tithes, set: setTithes },
                        { label: 'Ofertas Gerais', val: offers, set: setOffers },
                        { label: 'Ofertas Especiais', val: specialOffers, set: setSpecialOffers }
                      ].map(item => (
                        <div key={item.label} className="space-y-1">
                           <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">{item.label}</label>
                           <input type="number" disabled={readOnly} value={item.val || ''} onChange={e => item.set(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs outline-none focus:bg-white focus:border-indigo-100 transition-all" placeholder="0,00" />
                        </div>
                      ))}
                   </div>
                </div>

                {/* Receita Financeira Detalhada */}
                <div className="space-y-6">
                   <div className="flex items-center gap-2 border-b border-emerald-50 pb-2">
                     <Wallet className="text-emerald-500" size={16}/>
                     <h4 className="text-[10px] font-black uppercase text-emerald-600">Receita Financeira Detalhada</h4>
                   </div>
                   <div className="space-y-4">
                      {[
                        { label: 'Juros / Rendimentos Bancários', val: interestRevenue, set: setInterestRevenue },
                        { label: 'Aluguéis / Cessão de Espaço', val: rentRevenue, set: setRentRevenue }
                      ].map(item => (
                        <div key={item.label} className="space-y-1">
                           <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">{item.label}</label>
                           <input type="number" disabled={readOnly} value={item.val || ''} onChange={e => item.set(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs outline-none focus:bg-white focus:border-emerald-100 transition-all" placeholder="0,00" />
                        </div>
                      ))}

                      {/* Outras Receitas Dinâmicas */}
                      <div className="pt-4 space-y-3">
                         <div className="flex justify-between items-center">
                            <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Entradas Eventuais</span>
                            {!readOnly && <button onClick={() => setOtherRevenues([...otherRevenues, { id: crypto.randomUUID(), description: '', value: 0 }])} className="p-1.5 bg-slate-100 text-slate-500 rounded-lg hover:bg-indigo-600 hover:text-white transition-all"><Plus size={14}/></button>}
                         </div>
                         <div className="space-y-2">
                            {otherRevenues.map(item => (
                              <div key={item.id} className="flex gap-2 animate-in slide-in-from-top-2">
                                  <input type="text" disabled={readOnly} value={item.description} onChange={e => setOtherRevenues(otherRevenues.map(i => i.id === item.id ? {...i, description: e.target.value} : i))} className="flex-1 p-3 bg-slate-50 rounded-xl text-[10px] font-bold outline-none focus:bg-white" placeholder="Ex: Bazar, Doação Única" />
                                  <input type="number" disabled={readOnly} value={item.value || ''} onChange={e => setOtherRevenues(otherRevenues.map(i => i.id === item.id ? {...i, value: Number(e.target.value)} : i))} className="w-24 p-3 bg-slate-50 rounded-xl text-[10px] font-black outline-none focus:bg-white" placeholder="0,00" />
                                  {!readOnly && <button onClick={() => setOtherRevenues(otherRevenues.filter(i => i.id !== item.id))} className="p-2 text-rose-500"><Trash2 size={14}/></button>}
                              </div>
                            ))}
                         </div>
                      </div>
                   </div>
                </div>
             </div>
          </div>
        )}

        {activeTab === 'DESPESAS' && (
          <div className="space-y-10 animate-in slide-in-from-right-4">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                {/* Despesas de Manutenção da Unidade */}
                <div className="space-y-6">
                   <h4 className="text-[10px] font-black uppercase text-rose-500 border-b border-rose-50 pb-2">Manutenção e Utilidades Unidade</h4>
                   <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      {[
                        { label: 'Aluguel Prédio', val: rent, set: setRent },
                        { label: 'Energia Elétrica', val: energy, set: setEnergy },
                        { label: 'Água / Saneamento', val: water, set: setWater },
                        { label: 'Internet / Telefone', val: internet, set: setInternet },
                        { label: 'Limpeza / Produtos', val: cleaning, set: setCleaning },
                        { label: 'Manutenção / Reparos', val: maintenance, set: setMaintenance }
                      ].map(item => (
                        <div key={item.label} className="space-y-1">
                           <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">{item.label}</label>
                           <input type="number" disabled={readOnly} value={item.val || ''} onChange={e => item.set(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs outline-none focus:bg-white focus:border-rose-100 transition-all" placeholder="0,00" />
                        </div>
                      ))}
                   </div>
                </div>

                {/* Despesas de Atividades e Fins Sociais */}
                <div className="space-y-6">
                   <h4 className="text-[10px] font-black uppercase text-slate-900 border-b border-slate-50 pb-2">Atividades e Fins Sociais</h4>
                   <div className="space-y-4">
                      {[
                        { label: 'Oferta p/ Missões / Evangelismo', val: missions, set: setMissions },
                        { label: 'Assistência Social / Cestas', val: social, set: setSocial }
                      ].map(item => (
                        <div key={item.label} className="space-y-1">
                           <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">{item.label}</label>
                           <input type="number" disabled={readOnly} value={item.val || ''} onChange={e => item.set(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs outline-none focus:bg-white focus:border-indigo-100 transition-all" placeholder="0,00" />
                        </div>
                      ))}

                      {/* Outras Despesas Dinâmicas */}
                      <div className="pt-4 space-y-3">
                         <div className="flex justify-between items-center">
                            <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Outras Despesas Variáveis</span>
                            {!readOnly && <button onClick={() => setOtherExpenses([...otherExpenses, { id: crypto.randomUUID(), description: '', value: 0 }])} className="p-1.5 bg-slate-100 text-slate-500 rounded-lg hover:bg-rose-600 hover:text-white transition-all"><Plus size={14}/></button>}
                         </div>
                         <div className="space-y-2">
                            {otherExpenses.map(item => (
                              <div key={item.id} className="flex gap-2 animate-in slide-in-from-top-2">
                                  <input type="text" disabled={readOnly} value={item.description} onChange={e => setOtherExpenses(otherExpenses.map(i => i.id === item.id ? {...i, description: e.target.value} : i))} className="flex-1 p-3 bg-slate-50 rounded-xl text-[10px] font-bold outline-none focus:bg-white" placeholder="Descrição" />
                                  <input type="number" disabled={readOnly} value={item.value || ''} onChange={e => setOtherExpenses(otherExpenses.map(i => i.id === item.id ? {...i, value: Number(e.target.value)} : i))} className="w-24 p-3 bg-slate-50 rounded-xl text-[10px] font-black outline-none focus:bg-white" placeholder="0,00" />
                                  {!readOnly && <button onClick={() => setOtherExpenses(otherExpenses.filter(i => i.id !== item.id))} className="p-2 text-rose-500"><Trash2 size={14}/></button>}
                              </div>
                            ))}
                         </div>
                      </div>
                   </div>
                </div>
             </div>
          </div>
        )}

        {activeTab === 'ANEXOS' && (
          <div className="space-y-6 animate-in slide-in-from-right-4">
             {!readOnly && (
               <div onClick={() => fileInputRef.current?.click()} className="border-2 border-dashed border-slate-200 rounded-[2rem] p-12 text-center hover:border-indigo-300 cursor-pointer group transition-all">
                 <UploadCloud size={48} className="mx-auto text-slate-300 group-hover:text-indigo-500 mb-4 transition-colors" />
                 <h4 className="text-xs font-black uppercase text-slate-500 group-hover:text-indigo-600">Anexar Comprovantes / Fotos</h4>
                 <p className="text-[7px] font-bold text-slate-400 uppercase mt-2">Toque para selecionar arquivos</p>
                 <input type="file" ref={fileInputRef} className="hidden" multiple accept="image/*" onChange={handleFileChange} />
               </div>
             )}
             {isCompressing && <div className="flex items-center justify-center gap-2 text-indigo-500 font-black text-[9px] uppercase"><RefreshCw size={14} className="animate-spin" /> Processando Imagens...</div>}
             <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {attachments.map((at, idx) => (
                  <div key={idx} className="relative rounded-2xl overflow-hidden aspect-square border group shadow-sm hover:shadow-md transition-all">
                    <img src={at.data} className="w-full h-full object-cover" />
                    {!readOnly && (
                      <button onClick={() => setAttachments(attachments.filter((_, i) => i !== idx))} className="absolute top-2 right-2 p-2 bg-rose-600/80 backdrop-blur-sm text-white rounded-lg opacity-0 group-hover:opacity-100 transition-opacity">
                        <Trash2 size={14}/>
                      </button>
                    )}
                  </div>
                ))}
             </div>
          </div>
        )}

        {activeTab === 'RESUMO' && (
          <div className="space-y-8 animate-in slide-in-from-right-4">
             <div className="flex items-center justify-between border-b border-slate-50 pb-6">
                <div className="flex items-center gap-4">
                  <div className="w-16 h-16 bg-slate-50 rounded-2xl p-2 border border-slate-100 flex items-center justify-center">
                    {instLogo ? <img src={instLogo} className="max-w-full max-h-full object-contain" /> : <Building2 className="text-slate-200" />}
                  </div>
                  <div>
                    <h3 className="text-sm font-black text-slate-900 uppercase tracking-tight">{session.institution}</h3>
                    <p className="text-[7px] font-black text-indigo-500 uppercase tracking-widest">Resumo Consolidado Detalhado</p>
                  </div>
                </div>
                <div className="text-right">
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Referência</p>
                   <p className="text-xs font-black text-slate-900">{date.split('-').reverse().join('/')}</p>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Repasses */}
                <div className="space-y-4">
                   <h4 className="text-[10px] font-black uppercase text-slate-900 border-b border-slate-100 pb-2">Repasses Ministeriais</h4>
                   <div className="space-y-3">
                     <div className="flex justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                        <span className="text-[9px] font-black uppercase text-slate-400">Receita Bruta Total</span>
                        <span className="text-[10px] font-black text-slate-900">{formatBRL(totalRevenue)}</span>
                     </div>
                     <div className="flex justify-between p-4 bg-amber-50 rounded-2xl border border-amber-100/50">
                        <span className="text-[9px] font-black uppercase text-amber-600">Sede (20%)</span>
                        <span className="text-[10px] font-black text-amber-700">- {formatBRL(sedeExpense)}</span>
                     </div>
                     <div className="flex justify-between p-4 bg-amber-50 rounded-2xl border border-amber-100/50">
                        <span className="text-[9px] font-black uppercase text-amber-600">Prebenda (20%)</span>
                        <span className="text-[10px] font-black text-amber-700">- {formatBRL(prebendaExpense)}</span>
                     </div>
                     <div className="flex justify-between p-4 bg-emerald-50 rounded-2xl border border-emerald-100/50">
                        <span className="text-[9px] font-black uppercase text-emerald-600">Líquido p/ Unidade (60%)</span>
                        <span className="text-[10px] font-black text-emerald-700">{formatBRL(revenue60)}</span>
                     </div>
                   </div>
                </div>

                {/* Saldo Final */}
                <div className="space-y-4">
                   <h4 className="text-[10px] font-black uppercase text-slate-900 border-b border-slate-100 pb-2">Resultado Unidade</h4>
                   <div className="space-y-3">
                    <div className="flex justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                        <span className="text-[9px] font-black uppercase text-slate-400">Gasto Total Detalhado</span>
                        <span className="text-[10px] font-black text-rose-600">- {formatBRL(totalFixedExpenses)}</span>
                    </div>
                    <div className="flex justify-between p-5 bg-slate-950 rounded-[2rem] text-white shadow-xl shadow-slate-200">
                        <div className="flex flex-col">
                          <span className="text-[10px] font-black uppercase text-indigo-400 tracking-widest">Saldo GU</span>
                          <span className="text-[7px] font-bold text-slate-500 uppercase">Líquido Acumulado</span>
                        </div>
                        <span className="text-xl font-black text-emerald-400 self-center">{formatBRL(saldoGU)}</span>
                    </div>
                    <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                      <div className="flex justify-between items-center mb-1">
                        <span className="text-[8px] font-black uppercase text-slate-400">Saldo Geral de Caixa</span>
                        <span className="text-[10px] font-black text-slate-900">{formatBRL(currentBalance)}</span>
                      </div>
                      <p className="text-[6px] font-bold text-slate-400 uppercase">* Saldo Anterior + Saldo GU</p>
                    </div>
                   </div>
                </div>
             </div>
          </div>
        )}
      </div>

      {/* Action Footer */}
      <div className="flex gap-4 px-4 sm:px-0">
        {activeTab !== 'RESUMO' ? (
          <button onClick={() => { const tabs: FormTab[] = ['RECEITAS', 'DESPESAS', 'ANEXOS', 'RESUMO']; const idx = tabs.indexOf(activeTab); setActiveTab(tabs[idx + 1]); }} className="flex-1 py-5 bg-slate-900 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 active-scale shadow-xl shadow-slate-200">
            Próxima Etapa <ArrowRight size={18}/>
          </button>
        ) : (
          <button onClick={handleSubmit} disabled={isSaving || (readOnly && session.role !== 'ADMIN')} className={`flex-1 py-5 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 active-scale shadow-xl ${(readOnly && session.role !== 'ADMIN') ? 'bg-slate-300 shadow-none cursor-not-allowed' : 'bg-indigo-600 shadow-indigo-200'}`}>
            {isSaving ? <RefreshCw className="animate-spin" size={20}/> : (readOnly && session.role !== 'ADMIN') ? 'Apenas Visualização' : <><CheckCircle size={20}/> Salvar e Finalizar Relatório</>}
          </button>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { FinancialReport, UserSession } from '../types';
import { getReports, getSettings, deleteReport, updateReportLockStatus } from '../services/storageService';
import { Calendar, Search, RefreshCw, ImageIcon, X, Send, Eye, Download, FileDown, Edit3, Trash2, Lock, Unlock, AlertTriangle, Trash } from 'lucide-react';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface ReportHistoryProps {
  session: UserSession;
  onBack: () => void;
  onEdit?: (report: FinancialReport, readOnly?: boolean) => void;
  onGoToTrash?: () => void;
}

export const ReportHistory: React.FC<ReportHistoryProps> = ({ session, onBack, onEdit, onGoToTrash }) => {
  const [reports, setReports] = useState<FinancialReport[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  const fetchReports = async () => {
    try {
      setLoading(true);
      const allReports = await getReports();
      const filtered = allReports.filter(r => 
        session.role === 'ADMIN' || 
        r.institutionName.toLowerCase() === session.institution.toLowerCase()
      );
      setReports(filtered);
    } catch (err) { 
      console.error("Erro ao buscar relatórios:", err); 
    } finally { 
      setLoading(false); 
    }
  };

  useEffect(() => {
    fetchReports();
    const handleUpdate = () => fetchReports();
    window.addEventListener('reports-updated', handleUpdate);
    return () => window.removeEventListener('reports-updated', handleUpdate);
  }, [session.institution]);

  const handleDeleteReport = async (id: string) => {
    if (confirm("Deseja realmente mover este relatório para a lixeira?")) {
      try {
        await deleteReport(id, session.name);
      } catch (err) {
        alert("Erro ao excluir. Verifique sua conexão ou permissões.");
      }
    }
  };

  const handleToggleLock = async (report: FinancialReport) => {
    if (session.role !== 'ADMIN') return;
    const newStatus = !report.locked;
    if (confirm(`Deseja ${newStatus ? 'FECHAR' : 'ABRIR'} este período para edições?`)) {
      try {
        await updateReportLockStatus(report.id, newStatus);
      } catch (err) {
        alert("Erro ao alterar bloqueio.");
      }
    }
  };

  const formatBRL = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

  const generatePDF = async (report: FinancialReport) => {
    const settings = await getSettings();
    const doc = new jsPDF() as any;
    const pageWidth = doc.internal.pageSize.getWidth();
    let currentY = 20;

    if (settings.logo) {
      try { 
        const logoWidth = 35;
        const logoHeight = 35;
        doc.addImage(settings.logo, 'PNG', (pageWidth / 2) - (logoWidth / 2), currentY, logoWidth, logoHeight); 
        currentY += logoHeight + 10;
      } catch (e) {
        currentY += 10;
      }
    }

    doc.setFontSize(14); doc.setFont("helvetica", "bold"); doc.setTextColor(30, 41, 59);
    doc.text(settings.institutionName.toUpperCase(), pageWidth / 2, currentY, { align: 'center' });
    currentY += 20;

    // Seção Receitas
    doc.autoTable({
      startY: currentY,
      head: [['Descritivo de Entradas (100%)', 'Valor']],
      body: [
        ['Dízimos', formatBRL(report.tithes)],
        ['Ofertas Gerais', formatBRL(report.offers)],
        ['Ofertas Especiais', formatBRL(report.specialOffers)],
        ['Receita Financeira (Juros/Aluguéis)', formatBRL(report.financialRevenue)],
        ...report.otherRevenues.map(r => [r.description || 'Outra Receita', formatBRL(r.value)]),
        [{ content: 'TOTAL BRUTO ENTRADAS', styles: { fontStyle: 'bold', fillColor: [241, 245, 249] } }, { content: formatBRL(report.totalRevenue), styles: { fontStyle: 'bold', halign: 'right', fillColor: [241, 245, 249] } }]
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
      columnStyles: { 1: { halign: 'right' } }
    });

    currentY = doc.lastAutoTable.finalY + 10;

    // Seção Despesas Detalhadas
    doc.autoTable({
      startY: currentY,
      head: [['Descritivo de Despesas Unidade', 'Valor']],
      body: [
        ['Aluguel do Prédio', formatBRL(report.rent)],
        ['Energia Elétrica', formatBRL(report.energy)],
        ['Água / Saneamento', formatBRL(report.water)],
        ['Internet / Telefone', formatBRL(report.internet)],
        ['Limpeza / Produtos', formatBRL(report.cleaning)],
        ['Manutenção / Reparos', formatBRL(report.maintenance)],
        ['Oferta Missões / Evangelismo', formatBRL(report.missions)],
        ['Assistência Social', formatBRL(report.social)],
        ...report.otherExpenses.map(e => [e.description || 'Outra Despesa', formatBRL(e.value)]),
        [{ content: 'TOTAL DESPESAS UNIDADE', styles: { fontStyle: 'bold', fillColor: [254, 242, 242] } }, { content: formatBRL(report.totalFixedExpenses), styles: { fontStyle: 'bold', halign: 'right', fillColor: [254, 242, 242] } }]
      ],
      theme: 'grid',
      headStyles: { fillColor: [244, 63, 94] },
      columnStyles: { 1: { halign: 'right' } }
    });

    currentY = doc.lastAutoTable.finalY + 15;
    doc.setFontSize(12); doc.setTextColor(15, 23, 42);
    doc.text(`SALDO ANTERIOR: ${formatBRL(report.previousBalance)}`, 15, currentY);
    currentY += 8;
    doc.text(`SALDO LÍQUIDO DA SEMANA (GU): ${formatBRL(report.saldoGU)}`, 15, currentY);
    currentY += 8;
    doc.setFont("helvetica", "bold");
    doc.text(`SALDO ATUAL EM CAIXA: ${formatBRL(report.currentBalance)}`, 15, currentY);

    doc.save(`ADGU_Relatorio_${report.institutionName.replace(/\s+/g, '_')}_${report.date}.pdf`);
  };

  const filtered = reports.filter(r => r.institutionName.toLowerCase().includes(searchTerm.toLowerCase()));

  const canManage = (report: FinancialReport) => {
    if (session.role === 'ADMIN') return true;
    const isSameUnit = report.institutionName.toLowerCase() === session.institution.toLowerCase();
    const isNotLocked = !report.locked;
    return isSameUnit && isNotLocked;
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      <div className="flex flex-col md:flex-row gap-4">
        <div className="bg-white p-5 rounded-[2rem] border border-slate-100 shadow-soft flex-1 flex gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
            <input 
              type="text" 
              placeholder="Buscar unidade ou data..." 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)} 
              className="w-full pl-12 pr-4 py-3.5 bg-slate-50 rounded-2xl border border-transparent outline-none font-bold text-xs focus:bg-white focus:border-indigo-100 transition-all" 
            />
          </div>
        </div>

        {session.role === 'ADMIN' && (
          <button 
            onClick={onGoToTrash}
            className="p-5 bg-white text-slate-400 border border-slate-100 rounded-[2rem] shadow-soft hover:text-rose-500 transition-colors flex items-center gap-3 active-scale"
          >
            <Trash size={20} />
            <span className="text-[10px] font-black uppercase tracking-widest hidden md:inline">Lixeira</span>
          </button>
        )}
      </div>

      <div className="grid gap-4">
        {loading ? (
          <div className="py-20 flex flex-col items-center justify-center gap-4">
            <RefreshCw className="animate-spin text-indigo-500" size={32} />
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizando Banco de Dados...</p>
          </div>
        ) : filtered.length === 0 ? (
          <div className="py-20 text-center bg-white rounded-[2rem] border border-dashed border-slate-200">
            <FileDown size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nenhum relatório encontrado</p>
          </div>
        ) : (
          filtered.map(report => (
            <div key={report.id} className={`bg-white p-6 rounded-[2.5rem] border shadow-sm flex flex-col sm:flex-row items-center justify-between group transition-all gap-4 ${report.locked ? 'bg-slate-50/50 border-slate-100' : 'border-slate-50 hover:border-indigo-100'}`}>
              <div className="flex items-center gap-4 w-full sm:w-auto">
                <div className={`p-4 rounded-3xl transition-all shadow-sm ${report.locked ? 'bg-slate-200 text-slate-500' : 'bg-indigo-50 text-indigo-500'}`}>
                  {report.locked ? <Lock size={28} /> : <Calendar size={28} />}
                </div>
                <div>
                  <div className="flex items-center gap-2">
                    <h4 className="text-xs font-black uppercase text-slate-900 tracking-tight">{report.date.split('-').reverse().join('/')}</h4>
                    {report.locked && <span className="bg-amber-100 text-amber-700 px-2 py-0.5 rounded-full text-[6px] font-black uppercase tracking-tighter">Período Fechado</span>}
                  </div>
                  <p className="text-[8px] font-black text-indigo-500 uppercase tracking-widest">{report.institutionName}</p>
                  <p className="text-[10px] font-black text-emerald-600 mt-1">{formatBRL(report.saldoGU)}</p>
                </div>
              </div>

              <div className="flex flex-wrap justify-center sm:justify-end gap-2 w-full sm:w-auto">
                {session.role === 'ADMIN' && (
                  <button onClick={() => handleToggleLock(report)} className={`p-3 rounded-2xl active-scale transition-colors ${report.locked ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`} title={report.locked ? "Abrir Edição" : "Trancar Período"}>
                    {report.locked ? <Unlock size={18}/> : <Lock size={18}/>}
                  </button>
                )}

                <button onClick={() => onEdit?.(report, true)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-slate-100 transition-colors active-scale" title="Visualizar">
                  <Eye size={18}/>
                </button>

                {canManage(report) && (
                  <>
                    <button onClick={() => onEdit?.(report, false)} className="p-3 bg-indigo-50 text-indigo-600 rounded-2xl hover:bg-indigo-600 hover:text-white transition-all active-scale" title="Editar">
                      <Edit3 size={18}/>
                    </button>
                    <button onClick={() => handleDeleteReport(report.id)} className="p-3 bg-rose-50 text-rose-500 rounded-2xl hover:bg-rose-500 hover:text-white transition-all active-scale" title="Excluir">
                      <Trash2 size={18}/>
                    </button>
                  </>
                )}

                <button onClick={() => generatePDF(report)} className="p-3 px-5 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center gap-2 hover:bg-emerald-600 hover:text-white transition-all active-scale shadow-sm">
                  <Download size={18} />
                  <span className="text-[8px] font-black uppercase tracking-widest">PDF</span>
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

