    currentY = doc.lastAutoTable.finalY + 12;
    const colWidth = (pageWidth - (margin * 2) - 10) / 2;

    doc.setFontSize(8); doc.setFont("helvetica", "bold"); doc.setTextColor(30, 41, 59);
    doc.text("ENTRADAS CONSOLIDADAS", margin, currentY);
