                  const monthName = ["Jan", "Fev", "Mar", "Abr", "Mai", "Jun", "Jul", "Ago", "Set", "Out", "Nov", "Dez"][parseInt(mm)-1];
                  return <option key={m} value={m}>{monthName} / {y}</option>
                })}
                {filterType === 'YEAR' && periods.years.map(y => <option key={y} value={y}>{y}</option>)}
