      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        <div className="bg-slate-950 p-6 rounded-[2rem] text-white shadow-xl flex flex-col justify-between h-[160px] relative overflow-hidden">
