import React, { useState, useEffect, useRef } from 'react';
import { FinancialReport, MiscItem, UserSession } from '../types';
import { CheckCircle, Calculator, Info, Plus, Trash2, ArrowRight, ArrowLeft, UploadCloud, RefreshCw, FileText, AlertCircle, Building2, TrendingUp, Wallet } from 'lucide-react';
import { saveReport, getSettings } from '../services/storageService';

interface ReportFormProps {
  session: UserSession;
  initialData?: FinancialReport;
  readOnly?: boolean;
  onFinished: () => void;
  onCancel: () => void;
}

type FormTab = 'RECEITAS' | 'DESPESAS' | 'ANEXOS' | 'RESUMO';

export const ReportForm: React.FC<ReportFormProps> = ({ session, initialData, readOnly = false, onFinished, onCancel }) => {
  const [activeTab, setActiveTab] = useState<FormTab>('RECEITAS');
  const [date, setDate] = useState(initialData?.date || new Date().toISOString().split('T')[0]);

  const [tithes, setTithes] = useState(initialData?.tithes || 0);
  const [offers, setOffers] = useState(initialData?.offers || 0);
  const [specialOffers, setSpecialOffers] = useState(initialData?.specialOffers || 0);
  const [interestRevenue, setInterestRevenue] = useState(initialData?.interestRevenue || 0);
  const [rentRevenue, setRentRevenue] = useState(initialData?.rentRevenue || 0);
  const [otherRevenues, setOtherRevenues] = useState<MiscItem[]>(initialData?.otherRevenues || []);

  const [rent, setRent] = useState(initialData?.rent || 0);
  const [water, setWater] = useState(initialData?.water || 0);
  const [energy, setEnergy] = useState(initialData?.energy || 0);
  const [internet, setInternet] = useState(initialData?.internet || 0);
  const [cleaning, setCleaning] = useState(initialData?.cleaning || 0);
  const [maintenance, setMaintenance] = useState(initialData?.maintenance || 0);
  const [missions, setMissions] = useState(initialData?.missions || 0);
  const [social, setSocial] = useState(initialData?.social || 0);
  const [otherExpenses, setOtherExpenses] = useState<MiscItem[]>(initialData?.otherExpenses || []);

  const [attachments, setAttachments] = useState<{ name: string; type: string; data: string }[]>(initialData?.attachments || []);
  const [isSaving, setIsSaving] = useState(false);
  const [saveError, setSaveError] = useState<string | null>(null);
  const [isCompressing, setIsCompressing] = useState(false);
  const [previousBalance, setPreviousBalance] = useState(initialData?.previousBalance || 0);
  const [instLogo, setInstLogo] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    getSettings().then(s => setInstLogo(s.logo || null));
  }, []);

  const isCamposBelos = (initialData?.institutionName || session.institution).toLowerCase().replace(/\s+/g, '').includes('camposbelos');

  const compressImage = (base64Str: string): Promise<string> => {
    return new Promise((resolve) => {
      const img = new Image();
      img.src = base64Str;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX_WIDTH = 1200;
        let width = img.width;
        let height = img.height;
        if (width > MAX_WIDTH) { height *= MAX_WIDTH / width; width = MAX_WIDTH; }
        canvas.width = width; canvas.height = height;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL('image/jpeg', 0.6));
      };
    });
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (readOnly) return;
    const files = e.target.files;
    if (!files) return;
    setIsCompressing(true);
    for (const file of Array.from(files) as File[]) {
      try {
        const base64: string = await new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
        });
        const compressed = await compressImage(base64);
        setAttachments(prev => [...prev, { name: file.name, type: 'image/jpeg', data: compressed }]);
      } catch (err) { console.error(err); }
    }
    setIsCompressing(false);
  };

  const sumOtherRevenues = otherRevenues.reduce((acc, curr) => acc + (curr.value || 0), 0);
  const financialRevenueTotal = interestRevenue + rentRevenue;
  const totalRevenue = (Number(tithes) || 0) + (Number(offers) || 0) + (Number(specialOffers) || 0) + financialRevenueTotal + sumOtherRevenues;

  const sedeExpense = isCamposBelos ? 0 : totalRevenue * 0.20;
  const prebendaExpense = isCamposBelos ? 0 : totalRevenue * 0.20;
  const revenue60 = isCamposBelos ? totalRevenue : totalRevenue * 0.60;

  const sumOtherExpenses = otherExpenses.reduce((acc, curr) => acc + (curr.value || 0), 0);
  const totalFixedExpenses = (Number(rent) || 0) + (Number(water) || 0) + (Number(energy) || 0) + 
                            (Number(internet) || 0) + (Number(cleaning) || 0) + (Number(maintenance) || 0) + 
                            (Number(missions) || 0) + (Number(social) || 0) + sumOtherExpenses;

  const totalExpenses = sedeExpense + prebendaExpense + totalFixedExpenses;
  const saldoGU = revenue60 - totalFixedExpenses;
  const currentBalance = previousBalance + saldoGU;

  const formatBRL = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

  const handleSubmit = async () => {
    if (readOnly && session.role !== 'ADMIN') { onFinished(); return; }
    setIsSaving(true);
    setSaveError(null);
    const report: FinancialReport = {
      id: initialData?.id || crypto.randomUUID(),
      date, 
      institutionName: initialData?.institutionName || session.institution,
      reporterName: initialData?.reporterName || session.name, 
      userId: initialData?.userId || session.id,
      locked: initialData?.locked || false, 

      tithes, offers, specialOffers, 
      interestRevenue, rentRevenue, 
      financialRevenue: financialRevenueTotal, 
      otherRevenues,

      rent, water, energy, internet, cleaning, maintenance, missions, social,
      otherExpenses, 

      totalRevenue, 
      totalFixedExpenses, 
      sedeExpense, 
      prebendaExpense, 
      totalExpenses, 
      saldoGU, 
      currentBalance, 
      previousBalance, 
      attachments, 
      createdAt: initialData?.createdAt || new Date().toISOString()
    };
    try {
      await saveReport(report);
      onFinished();
    } catch (err: any) { 
      console.error(err);
      setSaveError(`Falha ao salvar: ${err.message || 'Erro de conexão'}`);
    } finally { setIsSaving(false); }
  };

  return (
    <div className="space-y-8 max-w-5xl mx-auto animate-in fade-in duration-700 pb-10">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 px-4">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-3 bg-white text-slate-400 rounded-xl shadow-sm hover:text-indigo-600 transition-colors active-scale"><ArrowLeft size={20}/></button>
          <div>
            <h2 className="text-xl font-black text-slate-900 uppercase tracking-tight">{readOnly ? 'Visualização Detalhada' : initialData ? 'Ajustar Fechamento' : 'Novo Fechamento'}</h2>
            <p className="text-[7px] font-black text-slate-400 uppercase tracking-widest">{session.institution}</p>
          </div>
        </div>
        {initialData?.locked && (
           <div className="bg-amber-50 text-amber-600 px-4 py-2 rounded-2xl border border-amber-100 flex items-center gap-2">
              <Calculator size={14}/>
              <span className="text-[8px] font-black uppercase tracking-widest">Apenas Leitura</span>
           </div>
        )}
      </div>

      {/* Tabs */}
      <div className="flex bg-white p-2 rounded-[1.5rem] shadow-soft border border-slate-50 overflow-x-auto no-scrollbar">
        {(['RECEITAS', 'DESPESAS', 'ANEXOS', 'RESUMO'] as FormTab[]).map(tab => (
          <button key={tab} onClick={() => setActiveTab(tab)} className={`flex-1 min-w-[100px] py-4 px-6 rounded-2xl text-[9px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>{tab}</button>
        ))}
      </div>

      {/* Content */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 p-6 md:p-10 shadow-sm min-h-[400px]">
        {saveError && (
          <div className="mb-6 p-4 bg-rose-50 border border-rose-100 rounded-2xl flex items-center gap-3 text-rose-600 animate-in shake duration-300">
            <AlertCircle size={20} />
            <p className="text-[10px] font-black uppercase">{saveError}</p>
          </div>
        )}

        {activeTab === 'RECEITAS' && (
          <div className="space-y-10 animate-in slide-in-from-right-4">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Data Referência</label>
                  <input type="date" disabled={readOnly} value={date} onChange={e => setDate(e.target.value)} className="w-full p-4 bg-slate-50 rounded-2xl border border-transparent font-bold text-xs focus:bg-white focus:border-indigo-100 transition-all outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Saldo Anterior Acumulado</label>
                  <input type="number" disabled={readOnly} value={previousBalance} onChange={e => setPreviousBalance(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl border border-transparent font-black text-xs focus:bg-white focus:border-indigo-100 transition-all outline-none" />
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-6">
                   <div className="flex items-center gap-2 border-b border-indigo-50 pb-2">
                     <TrendingUp className="text-indigo-500" size={16}/>
                     <h4 className="text-[9px] font-black uppercase text-indigo-500">Entradas Ministeriais (100%)</h4>
                   </div>
                   <div className="space-y-4">
                      {[
                        { label: 'Dízimos', val: tithes, set: setTithes },
                        { label: 'Ofertas Gerais', val: offers, set: setOffers },
                        { label: 'Ofertas Especiais', val: specialOffers, set: setSpecialOffers }
                      ].map(item => (
                        <div key={item.label} className="space-y-1">
                           <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">{item.label}</label>
                           <input type="number" disabled={readOnly} value={item.val || ''} onChange={e => item.set(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs outline-none focus:bg-white focus:border-indigo-100 transition-all" placeholder="0,00" />
                        </div>
                      ))}
                   </div>
                </div>

                <div className="space-y-6">
                   <div className="flex items-center gap-2 border-b border-emerald-50 pb-2">
                     <Wallet className="text-emerald-500" size={16}/>
                     <h4 className="text-[9px] font-black uppercase text-emerald-600">Receita Financeira Detalhada</h4>
                   </div>
                   <div className="space-y-4">
                      {[
                        { label: 'Juros / Rendimentos Bancários', val: interestRevenue, set: setInterestRevenue },
                        { label: 'Aluguéis / Cessão de Espaço', val: rentRevenue, set: setRentRevenue }
                      ].map(item => (
                        <div key={item.label} className="space-y-1">
                           <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">{item.label}</label>
                           <input type="number" disabled={readOnly} value={item.val || ''} onChange={e => item.set(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs outline-none focus:bg-white focus:border-emerald-100 transition-all" placeholder="0,00" />
                        </div>
                      ))}

                      <div className="pt-4 space-y-3">
                         <div className="flex justify-between items-center">
                            <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Entradas Eventuais</span>
                            {!readOnly && <button onClick={() => setOtherRevenues([...otherRevenues, { id: crypto.randomUUID(), description: '', value: 0 }])} className="p-1.5 bg-slate-100 text-slate-500 rounded-lg hover:bg-indigo-600 hover:text-white transition-all"><Plus size={14}/></button>}
                         </div>
                         <div className="space-y-2">
                            {otherRevenues.map(item => (
                              <div key={item.id} className="flex gap-2 animate-in slide-in-from-top-2">
                                  <input type="text" disabled={readOnly} value={item.description} onChange={e => setOtherRevenues(otherRevenues.map(i => i.id === item.id ? {...i, description: e.target.value} : i))} className="flex-1 p-3 bg-slate-50 rounded-xl text-[10px] font-bold outline-none focus:bg-white" placeholder="Ex: Bazar, Doação Única" />
                                  <input type="number" disabled={readOnly} value={item.value || ''} onChange={e => setOtherRevenues(otherRevenues.map(i => i.id === item.id ? {...i, value: Number(e.target.value)} : i))} className="w-24 p-3 bg-slate-50 rounded-xl text-[10px] font-black outline-none focus:bg-white" placeholder="0,00" />
                                  {!readOnly && <button onClick={() => setOtherRevenues(otherRevenues.filter(i => i.id !== item.id))} className="p-2 text-rose-500"><Trash2 size={14}/></button>}
                              </div>
                            ))}
                         </div>
                      </div>
                   </div>
                </div>
             </div>
          </div>
        )}

        {activeTab === 'DESPESAS' && (
          <div className="space-y-10 animate-in slide-in-from-right-4">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-6">
                   <h4 className="text-[9px] font-black uppercase text-rose-500 border-b border-rose-50 pb-2">Manutenção e Utilidades Unidade</h4>
                   <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      {[
                        { label: 'Aluguel Prédio', val: rent, set: setRent },
                        { label: 'Energia Elétrica', val: energy, set: setEnergy },
                        { label: 'Água / Saneamento', val: water, set: setWater },
                        { label: 'Internet / Telefone', val: internet, set: setInternet },
                        { label: 'Limpeza / Produtos', val: cleaning, set: setCleaning },
                        { label: 'Manutenção / Reparos', val: maintenance, set: setMaintenance }
                      ].map(item => (
                        <div key={item.label} className="space-y-1">
                           <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">{item.label}</label>
                           <input type="number" disabled={readOnly} value={item.val || ''} onChange={e => item.set(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs outline-none focus:bg-white focus:border-rose-100 transition-all" placeholder="0,00" />
                        </div>
                      ))}
                   </div>
                </div>

                <div className="space-y-6">
                   <h4 className="text-[9px] font-black uppercase text-slate-900 border-b border-slate-50 pb-2">Atividades e Fins Sociais</h4>
                   <div className="space-y-4">
                      {[
                        { label: 'Oferta p/ Missões / Evangelismo', val: missions, set: setMissions },
                        { label: 'Assistência Social / Cestas', val: social, set: setSocial }
                      ].map(item => (
                        <div key={item.label} className="space-y-1">
                           <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">{item.label}</label>
                           <input type="number" disabled={readOnly} value={item.val || ''} onChange={e => item.set(Number(e.target.value))} className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xs outline-none focus:bg-white focus:border-indigo-100 transition-all" placeholder="0,00" />
